static INT16U modbus_rxlen;

//! Byte swap unsigned short
INT16U swap_16U(INT16U val)
{
	return (val << 8) | (val >> 8);
}

//! Byte swap short
INT16S swap_16S(INT16S val)
{
	return (val << 8) | ((val >> 8) & 0xFF);
}

//! Byte swap unsigned int
INT32U swap_32U(INT32U val)
{
	val = ((val << 8) & 0xFF00FF00) | ((val >> 8) & 0xFF00FF);
	return (val << 16) | (val >> 16);
}

//! Byte swap int
INT32S swap_32S(INT32S val)
{
	val = ((val << 8) & 0xFF00FF00) | ((val >> 8) & 0xFF00FF);
	return (val << 16) | ((val >> 16) & 0xFFFF);
}

static INT08U m_ModbusResponse[2] = { 0, };

// addr 4부터 10*1=10개 Read
// REQ : 00 00 00 00 00 06 00 03 00 04 00 0A 
// RES : 00 00 00 00 00 17 00 03 14 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 

// addr 4부터 10*9=90개 Read
// REQ : 00 00 00 00 00 06 00 03 00 04 00 5A 
// RES : 00 00 00 00 00 B7 00 03 B4 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
void ModbusTcpRead(INT08U nSocket, INT16U nUnitID, INT16U ref, INT16U cnt)
{
	INT16U len;

#if DEBUG_MODBUS_HMI
	printf("[MODBUS_HMI] Request Read nSocket: %d, nTransactionID: %d, ReadRef:%d, WordCount:%d\r\n", \
		nSocket, nUnitID, ref, cnt);
#endif

	len = 6;   // 1(UnitID) + sizeof(ModbusTcpFC03SendSTR);  

	//ModbusTxPkt.TransactionID = nTransactionID;
	ModbusTxPkt.TransactionID = 0x000;
	ModbusTxPkt.ProtocolID = 0x0000;
	ModbusTxPkt.Length = len;
	ModbusTxPkt.UnitID = nUnitID;
	ModbusTxPkt.FunctionCode = FUNC_CODE_READ;

	ModbusTxPkt.FC03Send.ReferenceNumber = ref;
	ModbusTxPkt.FC03Send.WordCount = cnt;

	ModbusTxPkt.TransactionID = swap_16U(ModbusTxPkt.TransactionID);
	ModbusTxPkt.ProtocolID = swap_16U(ModbusTxPkt.ProtocolID);
	ModbusTxPkt.Length = swap_16U(ModbusTxPkt.Length);
	ModbusTxPkt.FC03Send.ReferenceNumber = swap_16U(ModbusTxPkt.FC03Send.ReferenceNumber);
	ModbusTxPkt.FC03Send.WordCount = swap_16U(ModbusTxPkt.FC03Send.WordCount);

	if (m_pgmEnv.HMI_Com_Port == HMI_COM_UPLINK)
	{
		tcp_client_SendBuf((INT08U*)&ModbusTxPkt.TransactionID, len + 6);
	}
	else
	{
		m_ModbusResponse[nSocket] = 0;
		Fpga_tcp_send(nSocket, (INT08U*)&ModbusTxPkt.TransactionID, len + 6);
	}
}

void ModbusTcpWrite(INT08U nSocket, INT08U nUnitID, INT16U ref, INT16U cnt, INT16U* data)
{
	INT16U i;
	INT16U len;

#if DEBUG_MODBUS_HMI
	printf("[MODBUS_HMI] Request Write Socket: %d, ID: %d, WriteRef:%d, WriteCount:%d\r\n",
		nSocket, nUnitID, ref, cnt);
#endif

	len = (cnt * 2) + 7;

	//ModbusTxPkt.TransactionID = nTransactionID;
	ModbusTxPkt.TransactionID = 0x0000;
	ModbusTxPkt.ProtocolID = 0x0000;
	ModbusTxPkt.Length = len;
	ModbusTxPkt.UnitID = 0;
	//ModbusTxPkt.UnitID = nUnitID;
	ModbusTxPkt.FunctionCode = FUNC_CODE_WRITE;

	ModbusTxPkt.FC16Send.ReferenceNumber = ref;
	ModbusTxPkt.FC16Send.WordCount = cnt;
	ModbusTxPkt.FC16Send.ByteCount = cnt * 2;

	ModbusTxPkt.TransactionID = swap_16U(ModbusTxPkt.TransactionID);
	ModbusTxPkt.ProtocolID = swap_16U(ModbusTxPkt.ProtocolID);
	ModbusTxPkt.Length = swap_16U(ModbusTxPkt.Length);
	ModbusTxPkt.FC16Send.ReferenceNumber = swap_16U(ModbusTxPkt.FC16Send.ReferenceNumber);
	ModbusTxPkt.FC16Send.WordCount = swap_16U(ModbusTxPkt.FC16Send.WordCount);

	for (i = 0; i < cnt; i++)  ModbusTxPkt.FC16Send.Data[i] = data[i];

	if (m_pgmEnv.HMI_Com_Port == HMI_COM_UPLINK)
	{
		tcp_client_SendBuf((INT08U*)&ModbusTxPkt.TransactionID, len + 6);
	}
	else
	{
		m_ModbusResponse[nSocket] = 0;
		Fpga_tcp_send(nSocket, (INT08U*)&ModbusTxPkt.TransactionID, len + 6);
	}
}

// REQ : 00 00 00 00 00 1F 00 17 00 04 00 0A 00 04 00 0A 14 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
// RES : 00 00 00 00 00 17 00 17 14 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 

// REQ : 00 00 00 00 00 BF 00 17 00 04 00 5A 00 04 00 5A B4 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
//       00 11 00 12 00 13 00 14 00 15 00 16 00 17 00 18 00 19 00 1A 
// RES : 00 00 00 00 00 B7 00 17 B4 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
//       00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 
void ModbusTcpWriteRead_1(INT08U nSocket, INT16U read_ref, INT16U read_cnt, INT16U write_ref, INT16U write_cnt, INT16U* data)
{
	INT16U i;
	INT16U len;

#if DEBUG_MODBUS_SEW
	printf("[MODBUS_SEW] Socket: %d, Read/Write Multiple Register ReadRef:%d, ReadCount:%d WriteRef:%d, WriteCount:%d\r\n",
		nSocket, read_ref, read_cnt, write_ref, write_cnt);
#endif

	len = (write_cnt * 2) + 11;

	ModbusTxPkt.TransactionID = 0x0000;
	ModbusTxPkt.ProtocolID = 0x0000;
	ModbusTxPkt.Length = len;
	ModbusTxPkt.UnitID = 0;
	ModbusTxPkt.FunctionCode = FUNC_CODE_WRITE_READ;

	ModbusTxPkt.FC23Send.ReadReferenceNumber = read_ref;
	ModbusTxPkt.FC23Send.ReadWordCount = read_cnt;
	ModbusTxPkt.FC23Send.WriteReferenceNumber = write_ref;
	ModbusTxPkt.FC23Send.WriteWordCount = write_cnt;
	ModbusTxPkt.FC23Send.WriteByteCount = write_cnt * 2;

	ModbusTxPkt.TransactionID = swap_16U(ModbusTxPkt.TransactionID);
	ModbusTxPkt.ProtocolID = swap_16U(ModbusTxPkt.ProtocolID);
	ModbusTxPkt.Length = swap_16U(ModbusTxPkt.Length);
	ModbusTxPkt.FC23Send.ReadReferenceNumber = swap_16U(ModbusTxPkt.FC23Send.ReadReferenceNumber);
	ModbusTxPkt.FC23Send.ReadWordCount = swap_16U(ModbusTxPkt.FC23Send.ReadWordCount);
	ModbusTxPkt.FC23Send.WriteReferenceNumber = swap_16U(ModbusTxPkt.FC23Send.WriteReferenceNumber);
	ModbusTxPkt.FC23Send.WriteWordCount = swap_16U(ModbusTxPkt.FC23Send.WriteWordCount);

	for (i = 0; i < write_cnt; i++)  ModbusTxPkt.FC23Send.Data[i] = data[i];

	m_ModbusResponse[nSocket] = 0;
	Fpga_tcp_send(nSocket, (INT08U*)&ModbusTxPkt.TransactionID, len + 6);
}

