void Store_SRM_RxPDO(INT08U Inv, INT16U control_word, INT32S position, UnitVelocitySTR* pVel)
{
	INT16S vel = 0;
	INT16S acc = 0;
	INT16S dec = 0;
	INT16U JerkTime = 0;

	double Calc_Jerk = 0;

	INT16U nMaxjerkTime = 0;
	INT16S nMax_vel = 0;
	INT16S nMax_acc_dec = 0;

	vel = pVel->Spd;
	acc = pVel->Acc;
	dec = pVel->Dec;

	Calc_Jerk = (double)(acc) / ((double)(pVel->Jerk) * 0.001);	// Jerk ms단위

	switch (Inv)
	{
	case INV_TRAVEL:
		nMax_vel = MAX_TRAVEL_VEL_AUTO;
		nMax_acc_dec = MAX_TRAVEL_ACC;
		nMaxjerkTime = 600;
		break;

	case INV_HOIST:
		nMax_vel = MAX_LIFT_VEL_AUTO_H;
		nMax_acc_dec = MAX_LIFT_ACC;
		nMaxjerkTime = 500;
		break;

	case INV_FORK_1:
		nMax_vel = MAX_FORK_VEL_AUTO;
		nMax_acc_dec = MAX_FORK_ACC;
		nMaxjerkTime = 600;
		break;

	default:
		nMax_vel = 100;
		nMax_acc_dec = MAX_FORK_ACC;
		nMaxjerkTime = 500;
		break;
	}

	if (vel > nMax_vel)  vel = nMax_vel;
	if (acc > nMax_acc_dec)  acc = nMax_acc_dec;
	if (dec > nMax_acc_dec)  dec = nMax_acc_dec;

	if (nMaxjerkTime < Calc_Jerk)
	{
		JerkTime = nMaxjerkTime;
		//m_TestStatus.Ctrl[DEBUG_CTR_4] = JerkTime;
	}
	else
	{
		JerkTime = (INT16U)Calc_Jerk;
	}

	//m_TestStatus.Ctrl[DEBUG_CTR_5] = JerkTime;

	m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.W = control_word;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.TargetPosition = position;			// mm    
	m_SRM_RxPDOQ[Inv].Last_RxPDO.Setpoint_Speed = vel;				// m/min 
	m_SRM_RxPDOQ[Inv].Last_RxPDO.Setpoint_Acc = acc;				// mm/s^2
	m_SRM_RxPDOQ[Inv].Last_RxPDO.Setpoint_Dec = dec;				// mm/s^2
	m_SRM_RxPDOQ[Inv].Last_RxPDO.JerkTime = JerkTime;				// mm/s^3
	/*
	Set_TestStatus(DEBUG_STR_46, control_word);
	Set_TestStatus(DEBUG_STR_47, position);
	Set_TestStatus(DEBUG_STR_48, vel);
	Set_TestStatus(DEBUG_STR_49, acc);
	Set_TestStatus(DEBUG_STR_50, dec);
	Set_TestStatus(DEBUG_STR_51, JerkTime);
	*/
	if (m_SRM_RxPDOQ[Inv].Set_Variable)
	{
		m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.B.Set_Variable = 1;
	}
	else
	{
		m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.B.Set_Variable = 0;
	}
}

void Store_SRM_RxPDO_1(INT08U Inv, INT16U nMode, INT16U control_word, INT32S position, UnitVelocitySTR* pVel)
{
	INT16S vel_mpm = 0;
	INT16S vel_mms = 0;
	INT16S acc = 0;
	INT16S dec = 0;
	INT16U JerkTime = 0;

	double Calc_Jerk = 0;

	INT16U nMaxjerkTime = 0;
	INT16S nMax_vel = 0;
	INT16S nMax_acc_dec = 0;

	vel_mpm = pVel->Spd;
	acc = pVel->Acc;
	dec = pVel->Dec;

	Calc_Jerk = (double)(acc) / ((double)(pVel->Jerk) * 0.001);	// Jerk ms단위

	switch (Inv)
	{
	case INV_TRAVEL:
		nMax_vel = MAX_TRAVEL_VEL_AUTO;
		nMax_acc_dec = MAX_TRAVEL_ACC;
		nMaxjerkTime = 600;
		break;

	case INV_HOIST:
		nMax_vel = MAX_LIFT_VEL_AUTO_H;
		nMax_acc_dec = MAX_LIFT_ACC;
		nMaxjerkTime = 500;
		break;

	case INV_FORK_1:
		nMax_vel = MAX_FORK_VEL_AUTO;
		nMax_acc_dec = MAX_FORK_ACC;
		nMaxjerkTime = 600;
		break;

	default:
		nMax_vel = 100;
		nMax_acc_dec = MAX_FORK_ACC;
		nMaxjerkTime = 500;
		break;
	}

	if (vel_mpm > nMax_vel)  vel_mpm = nMax_vel;
	if (acc > nMax_acc_dec)  acc = nMax_acc_dec;
	if (dec > nMax_acc_dec)  dec = nMax_acc_dec;

	if (nMaxjerkTime < Calc_Jerk)
	{
		JerkTime = nMaxjerkTime;
		//m_TestStatus.Ctrl[DEBUG_CTR_4] = JerkTime;
	}
	else
	{
		JerkTime = (INT16U)Calc_Jerk;
	}

	//m_TestStatus.Ctrl[DEBUG_CTR_5] = JerkTime;

	switch (Inv)
	{
	case INV_TRAVEL:
		m_SRM_PO_Que_1.LastBuf.Travel.Operating_mode = nMode;

		//vel_mms = (INT16S)((vel_mpm * 1000) / 60);	// m/min -> mm/s
		vel_mms = Calc_Velocity_mpm_mms(vel_mpm);
		//Set_TestStatus(DEBUG_STR_27, vel_mpm);
		//Set_TestStatus(DEBUG_STR_28, vel_mms);

		m_SRM_PO_Que_1.LastBuf.Travel.ControlWord.W = control_word;
		m_SRM_PO_Que_1.LastBuf.Travel.TargetPosition = position;		// mm    
		m_SRM_PO_Que_1.LastBuf.Travel.Setpoint_Speed = vel_mms;		// mm/s
		m_SRM_PO_Que_1.LastBuf.Travel.Setpoint_Acc = acc;				// mm/s^2
		m_SRM_PO_Que_1.LastBuf.Travel.Setpoint_Dec = dec;				// mm/s^2
		m_SRM_PO_Que_1.LastBuf.Travel.JerkTime = JerkTime;			// mm/s^3
		break;

	case INV_HOIST:
		m_SRM_PO_Que_1.LastBuf.Hoist.Operating_mode = nMode;

		//vel_mms = (INT16S)((vel_mpm * 1000) / 60);
		vel_mms = Calc_Velocity_mpm_mms(vel_mpm);
		//Set_TestStatus(DEBUG_STR_29, vel_mpm);
		//Set_TestStatus(DEBUG_STR_30, vel_mms);

		m_SRM_PO_Que_1.LastBuf.Hoist.ControlWord.W = control_word;
		m_SRM_PO_Que_1.LastBuf.Hoist.TargetPosition = position;		// mm    
		m_SRM_PO_Que_1.LastBuf.Hoist.Setpoint_Speed = vel_mms;		// mm/s
		m_SRM_PO_Que_1.LastBuf.Hoist.Setpoint_Acc = acc;				// mm/s^2
		m_SRM_PO_Que_1.LastBuf.Hoist.Setpoint_Dec = dec;				// mm/s^2
		m_SRM_PO_Que_1.LastBuf.Hoist.JerkTime = JerkTime;				// mm/s^3
		break;

	case INV_FORK_1:
		m_SRM_PO_Que_1.LastBuf.Fork.Operating_mode = nMode;

		//vel_mms = (INT16S)((vel_mpm * 1000) / 60);
		vel_mms = Calc_Velocity_mpm_mms(vel_mpm);
		//Set_TestStatus(DEBUG_STR_31, vel_mpm);
		//Set_TestStatus(DEBUG_STR_32, vel_mms);

		m_SRM_PO_Que_1.LastBuf.Fork.ControlWord.W = control_word;
		m_SRM_PO_Que_1.LastBuf.Fork.TargetPosition = position;		// mm    
		m_SRM_PO_Que_1.LastBuf.Fork.Setpoint_Speed = vel_mms;			// mm/s
		m_SRM_PO_Que_1.LastBuf.Fork.Setpoint_Acc = acc;				// mm/s^2
		m_SRM_PO_Que_1.LastBuf.Fork.Setpoint_Dec = dec;				// mm/s^2

		// 포크 위치제어는 저크 시간(ms)값 전달
		m_SRM_PO_Que_1.LastBuf.Fork.JerkTime = pVel->Jerk;			// ms
		//m_SRM_PO_Que.LastBuf.Fork.JerkTime = JerkTime;			// mm/s^3
		break;
	}
}

