void Store_SRM_Fork_RxPDO(INT16U control_word, INT16S nCmdVelocity)
{
	m_SRM_RxPDOQ[INV_FORK_1].Last_RxPDO.ControlWord.W = control_word;
	m_SRM_RxPDOQ[INV_FORK_1].Last_RxPDO.TargetPosition = 0;					// mm    
	m_SRM_RxPDOQ[INV_FORK_1].Last_RxPDO.Setpoint_Speed = nCmdVelocity;		// m/min 
	m_SRM_RxPDOQ[INV_FORK_1].Last_RxPDO.Setpoint_Acc = 0;					// mm/s^2
	m_SRM_RxPDOQ[INV_FORK_1].Last_RxPDO.Setpoint_Dec = 0;					// mm/s^2
	m_SRM_RxPDOQ[INV_FORK_1].Last_RxPDO.JerkTime = 0;						// mm/s^3
}

void Store_ReadParam_RxPDO_queue(INT08U Inv, INT08U nReadFlag, INT16U MainIndex, INT16U Subndex)
{
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.B.ReadParam = nReadFlag;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.B.WriteParam = 0;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ParamMainIndex = MainIndex;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ParamSubIndex = Subndex;

	memcpy((INT08U*)&m_SRM_RxPDOQ[Inv].Queue[m_SRM_RxPDOQ[Inv].Front], \
		(INT08U*)&m_SRM_RxPDOQ[Inv].Last_RxPDO, sizeof(MoviC_RxPDO));

	if (++m_SRM_RxPDOQ[Inv].Front >= MAX_SRM_RxPDO_Q_CNT)  m_SRM_RxPDOQ[Inv].Front = 0;
}

void Store_WriteParam_RxPDO_queue(INT08U Inv, INT08U nWriteFlag, INT16U MainIndex, INT16U Subndex, INT32S nData)
{
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.B.WriteParam = nWriteFlag;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.B.ReadParam = 0;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ParamMainIndex = MainIndex;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.ParamSubIndex = Subndex;

	m_SRM_RxPDOQ[Inv].Last_RxPDO.WriteParamData = nData;

	memcpy((INT08U*)&m_SRM_RxPDOQ[Inv].Queue[m_SRM_RxPDOQ[Inv].Front], \
		(INT08U*)&m_SRM_RxPDOQ[Inv].Last_RxPDO, sizeof(MoviC_RxPDO));

	if (++m_SRM_RxPDOQ[Inv].Front >= MAX_SRM_RxPDO_Q_CNT)  m_SRM_RxPDOQ[Inv].Front = 0;
}

void Store_InvParam_RxPDO_Queue(INT08U Inv, INT08U nSet, INT32S nRefOffset, INT32U nPosGain, INT08U nPosWindow)
{
	m_SRM_RxPDOQ[Inv].Set_Variable = nSet;

	m_SRM_RxPDOQ[Inv].Last_RxPDO.ControlWord.B.Set_Variable = nSet;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.Set_RefOffset = nRefOffset;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.Set_PosGain = nPosGain;
	m_SRM_RxPDOQ[Inv].Last_RxPDO.Set_PosWindow = (INT16U)nPosWindow;

	memcpy((INT08U*)&m_SRM_RxPDOQ[Inv].Queue[m_SRM_RxPDOQ[Inv].Front], \
		(INT08U*)&m_SRM_RxPDOQ[Inv].Last_RxPDO, sizeof(MoviC_RxPDO));

	if (++m_SRM_RxPDOQ[Inv].Front >= MAX_SRM_RxPDO_Q_CNT)  m_SRM_RxPDOQ[Inv].Front = 0;
}

// 1: Brake Off, 0 : Brake On
