			nControlWord_2.B.Jog_Positive = 1;
			nControlWord_2.B.Jog_Negative = 0;

			Store_SRM_RxPDO_2(INV_HOIST, OP_MODE_JOG_SPD, nControlWord_2.W, 0, &nVelocity);
