INT08U Motor_Manual_Fork1(INT08U nAct, INT08U VelType)
{
	UnitVelocitySTR nVelocity;

	ControlWord_A_t			nControlWord;
	MOVKIT_POS_Control_t	nControlWord_1;

#if DEBUG_FORK_MAN_CTR
	Set_TestStatus(DEBUG_STR_39, nAct);
	Set_TestStatus(DEBUG_STR_40, VelType);
#endif

	if (m_St.Inv_St[INV_FORK_1].Status2.IO_Control)
	{
#if DEBUG_FORK_MAN_CTR
		Set_TestStatus(DEBUG_STR_37, 2);
#endif

		if (Get_DI_State(IN_FK1_FAULT) == 1)	return M_CTR_ERROR_FALUT;

		// IO를 통한 포크부 구동 조건
		// DI01 : FK_JOG
		// DI02 : FK_JOG_R
		// DI03 : FK_JOG_L
		// 
		// - 정상 대기 상태
		// Off - DI01 : activation
		// Off - DI02 : positive direction of rotation
		// Off - DI03 : negative direction of rotation
		// 
		// - 정방향 구동
		// On - DI01 : activation
		// On - DI02 : positive direction of rotation
		// Off - DI03 : negative direction of rotation
		// 
		// - 정방향 구동 후 정지 시
		// Off - DI01 : activation
		// Off - DI02 : positive direction of rotation
		// Off - DI03 : negative direction of rotation
		// 
		// - 역방향 구동
		// On - DI01 : activation
		// Off - DI02 : positive direction of rotation
		// On - DI03 : negative direction of rotation
		// 
		// - 역방향 구동 후 정지 시
		// Off - DI01 : activation
		// Off - DI02 : positive direction of rotation
		// Off - DI03 : negative direction of rotation
		switch (nAct)
		{
		case JOG_FORK_APP_STOP:
		case JOG_FORK_STOP_1:
		case JOG_FORK_STOP_R:
		case JOG_FORK_STOP_L:
		case JOG_FORK_STOP_R_1:
		case JOG_FORK_STOP_L_1:
			DO_Control(OUT_FK1_JOG, 0);
			DO_Control(OUT_FK1_JOG_R, 0);
			DO_Control(OUT_FK1_JOG_L, 0);
#if DEBUG_FORK_MAN_CTR
			Set_TestStatus(DEBUG_STR_38, 1);
#endif
			break;

		case JOG_FORK_RIGHT:
			DO_Control(OUT_FK1_JOG, 1);
			DO_Control(OUT_FK1_JOG_R, 1);
			DO_Control(OUT_FK1_JOG_L, 0);

#if DEBUG_FORK_MAN_CTR
			Set_TestStatus(DEBUG_STR_38, 2);
#endif
			break;

		case JOG_FORK_LEFT:
			DO_Control(OUT_FK1_JOG, 1);
			DO_Control(OUT_FK1_JOG_R, 0);
			DO_Control(OUT_FK1_JOG_L, 1);

#if DEBUG_FORK_MAN_CTR
			Set_TestStatus(DEBUG_STR_38, 3);
#endif
			break;
		}
	}
	else
	{
#if DEBUG_FORK_MAN_CTR
		Set_TestStatus(DEBUG_STR_37, 1);
#endif

		if ((Get_Inverter_Fault_State(INV_FORK_1) == 1))	return M_CTR_ERROR_FALUT;
		if ((Get_Inverter_Ready_State(INV_FORK_1)) == 0)	return M_CTR_ERROR_NOT_READY;

		memset((INT08U*)&nVelocity, 0, sizeof(UnitVelocitySTR));

		nControlWord.W = 0;
		nControlWord_1.W = 0;


		if ((VelType == FORK_VEL_AUTO_H) || (VelType == FORK_VEL_AUTO_M) \
			|| (VelType == FORK_VEL_AUTO_L) \
			|| (VelType == FORK_VEL_AUTO_DEC_1) || (VelType == FORK_VEL_AUTO_DEC_2))
		{
			return M_CTR_ERROR_VELOCITY;
		}

		nControlWord.B.Mode = INV_MODE_JOG;

		if (nAct == JOG_FORK_APP_STOP)
		{
			// Stop
			memset((INT08U*)&nVelocity, 0x00, sizeof(UnitVelocitySTR));

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Jog_Positive = 0;
				nControlWord.B.Jog_Negative = 0;
				nControlWord.B.Enable_AppStop = 0;
				nControlWord.B.Enable_EmgStop = 1;
				nControlWord.B.Start = 0;
				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);
			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 0;
				nControlWord_1.B.Enable_AppStop = 0;

				nControlWord_1.B.Jog_Positive = 0;
				nControlWord_1.B.Jog_Negative = 0;

				nControlWord_1.B.Start = 0;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);
			}
		}
		else if (nAct == JOG_FORK_RIGHT)
		{
			// Right
			memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

			if (VelType == FORK_VEL_CREEP)
			{
				nVelocity.Acc = nVelocity.Dec;
			}

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Enable_AppStop = 1;
				nControlWord.B.Enable_EmgStop = 1;

				if (m_ExtSEnv2.ForkDrive.ManualDrive.ControlDir == 0)
				{
					// CW, 청라 SRM
					nControlWord.B.Jog_Positive = 0;
					nControlWord.B.Jog_Negative = 1;
				}
				else
				{
					// CCW, KCTC SRM
					nControlWord.B.Jog_Positive = 1;
					nControlWord.B.Jog_Negative = 0;
				}

				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);
			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 1;
				nControlWord_1.B.Enable_AppStop = 1;

				nControlWord_1.B.Jog_Positive = 1;
				nControlWord_1.B.Jog_Negative = 0;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);
			}
		}
		else if (nAct == JOG_FORK_LEFT)
		{
			// Left
			memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

			if (VelType == FORK_VEL_CREEP)
			{
				nVelocity.Acc = nVelocity.Dec;
			}

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Enable_AppStop = 1;
				nControlWord.B.Enable_EmgStop = 1;

				if (m_ExtSEnv2.ForkDrive.ManualDrive.ControlDir == 0)
				{
					nControlWord.B.Jog_Positive = 1;
					nControlWord.B.Jog_Negative = 0;
				}
				else
				{
					nControlWord.B.Jog_Positive = 0;
					nControlWord.B.Jog_Negative = 1;
				}

				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);
			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 1;
				nControlWord_1.B.Enable_AppStop = 1;

				nControlWord_1.B.Jog_Positive = 0;
				nControlWord_1.B.Jog_Negative = 1;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);
			}
		}
		else if (nAct == JOG_FORK_STOP_1)
		{
			memset((INT08U*)&nVelocity, 0x00, sizeof(UnitVelocitySTR));
			memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

			if (m_pgmEnv.Fork_Brake_Type == FORK_BRAKE_SEW)
			{
				nVelocity.Spd = 0;
			}
			else
			{
				// 환인제약 SRM
				// 포크 속도 '0' 제어가 안된다고 해서, 속도 1로 제어.
				// 정지 제어 처리 후, 500ms 이후에 브레이크 제어(Enable_AppStop = 0, Enable_EMGStop = 0)로 포크 정지.
				nVelocity.Spd = 1;
			}

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Jog_Positive = 0;
				nControlWord.B.Jog_Negative = 0;
				nControlWord.B.Enable_AppStop = 1;
				nControlWord.B.Enable_EmgStop = 1;

				nControlWord.B.Start = 0;

				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);
			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 1;
				nControlWord_1.B.Enable_AppStop = 1;

				nControlWord_1.B.Jog_Positive = 0;
				nControlWord_1.B.Jog_Negative = 0;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);
			}
		}
		else if (nAct == JOG_FORK_STOP_R)
		{
			memset((INT08U*)&nVelocity, 0x00, sizeof(UnitVelocitySTR));
			memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

			nVelocity.Spd = 0;

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Jog_Positive = 0;
				nControlWord.B.Jog_Negative = 0;

				nControlWord.B.Enable_AppStop = 1;
				nControlWord.B.Enable_EmgStop = 1;

				nControlWord.B.Start = 0;

				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);

			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 1;
				nControlWord_1.B.Enable_AppStop = 1;

				nControlWord_1.B.Jog_Positive = 0;
				nControlWord_1.B.Jog_Negative = 0;

				nControlWord_1.B.Start = 0;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);
			}
		}
		else if (nAct == JOG_FORK_STOP_R_1)
		{
			memset((INT08U*)&nVelocity, 0x00, sizeof(UnitVelocitySTR));
			memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

			nVelocity.Spd = 1;

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Jog_Positive = 0;
				nControlWord.B.Jog_Negative = 0;
				nControlWord.B.Enable_AppStop = 1;
				nControlWord.B.Enable_EmgStop = 1;

				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);
			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 1;
				nControlWord_1.B.Enable_AppStop = 1;

				nControlWord_1.B.Jog_Positive = 0;
				nControlWord_1.B.Jog_Negative = 0;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);
			}
		}
		else if (nAct == JOG_FORK_STOP_L)
		{
			memset((INT08U*)&nVelocity, 0x00, sizeof(UnitVelocitySTR));
			memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

			nVelocity.Spd = 0;

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Enable_AppStop = 1;
				nControlWord.B.Enable_EmgStop = 1;

				nControlWord.B.Jog_Positive = 0;
				nControlWord.B.Jog_Negative = 0;

				nControlWord.B.Start = 0;

				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);
			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 1;
				nControlWord_1.B.Enable_AppStop = 1;

				nControlWord_1.B.Jog_Positive = 0;
				nControlWord_1.B.Jog_Negative = 0;

				nControlWord_1.B.Start = 0;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);

			}
		}
		else if (nAct == JOG_FORK_STOP_L_1)
		{
			memset((INT08U*)&nVelocity, 0x00, sizeof(UnitVelocitySTR));
			memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

			nVelocity.Spd = 1;

			if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
			{
				nControlWord.B.Enable_AppStop = 1;
				nControlWord.B.Enable_EmgStop = 1;

				nControlWord.B.Jog_Positive = 0;
				nControlWord.B.Jog_Negative = 0;

				Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, 0, &nVelocity);
			}
			else
			{
				nControlWord_1.B.Enable_EmgStop = 1;
				nControlWord_1.B.Enable_AppStop = 1;

				nControlWord_1.B.Jog_Positive = 0;
				nControlWord_1.B.Jog_Negative = 0;

				Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_JOG_SPD, nControlWord_1.W, 0, &nVelocity);
			}
		}
	}
	
	

	return M_CTR_ERROR_NONE;
}

// Auto Fork Position Control Test
INT08U Auto_Position_Control_Fork(INT32S position, INT08U VelType)
{
	static INT08U s_PreVelType = 0;

	UnitVelocitySTR nCmdVelocity;

	ControlWord_A_t nControlWord;

	MOVKIT_POS_Control_t nControlWord_1;

	nControlWord.W = 0;
	nControlWord_1.W = 0;

	memset((INT08U*)&nCmdVelocity, 0, sizeof(UnitVelocitySTR));

	if ((m_SRM_Inverter_Error) || (Get_Inverter_Fault_State(INV_FORK_1))) return M_CTR_ERROR_FALUT;

	if (Get_Inverter_Ready_State(INV_FORK_1) == 0)	return M_CTR_ERROR_NOT_READY;

	if (Get_Inverter_Referenced_State(INV_FORK_1) == 0)		return M_CTR_ERROR_IPOS_REF;

	if ((VelType == FORK_VEL_AUTO_H) || (VelType == FORK_VEL_AUTO_M) || (VelType == FORK_VEL_AUTO_L))
	{
		memcpy(&nCmdVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));
		s_PreVelType = VelType;
	}
	else if ((VelType == FORK_VEL_AUTO_DEC_1) || (VelType == FORK_VEL_AUTO_DEC_2))
	{
		memcpy(&nCmdVelocity, &m_ExtSEnv2.ForkDrive.Vel[s_PreVelType], sizeof(UnitVelocitySTR));
		nCmdVelocity.Spd = m_ExtSEnv2.ForkDrive.Vel[VelType].Spd;
	}
	else if (VelType == FORK_VEL_EMG)
	{
		memcpy(&nCmdVelocity, &m_ExtSEnv2.ForkDrive.Vel[s_PreVelType], sizeof(UnitVelocitySTR));
		nCmdVelocity.Spd = 0;
		position = 0;
	}
	else if ((VelType == FORK_VEL_MAN_M) || (VelType == FORK_VEL_MAN_L) || (VelType == FORK_VEL_ORIGIN))
	{
		memcpy(&nCmdVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));
	}
	else
	{
		return M_CTR_ERROR_VELOCITY;
	}

	if (VelType != FORK_VEL_EMG)
	{
		if ((m_ExtSEnv2.ForkDrive.ManualDrive.LeftPos != 0) \
			&& (m_ExtSEnv2.ForkDrive.ManualDrive.RightPos != 0))
		{
			if ((position < m_ExtSEnv2.ForkDrive.ManualDrive.LeftPos) \
				|| (position > m_ExtSEnv2.ForkDrive.ManualDrive.RightPos))
			{
				return M_CTR_ERROR_CMD_TARGET_POS;
			}
		}
		else
		{
			return M_CTR_ERROR_CMD_TARGET_POS;
		}
	}

	//m_St.Inv_St[INV_FORK_1].Target_Pos = position;

	if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
	{
		nControlWord.B.Mode = INV_MODE_AUTO;
		nControlWord.B.Enable_AppStop = 1;
		nControlWord.B.Enable_EmgStop = 1;
		nControlWord.B.Start = 1;
		Store_SRM_RxPDO(INV_FORK_1, nControlWord.W, position, &nCmdVelocity);
	}
	else
	{
		nControlWord_1.B.Enable_EmgStop = 1;
		nControlWord_1.B.Enable_AppStop = 1;
		nControlWord_1.B.Start = 1;

		Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_ABSOLUTE_POS, nControlWord_1.W, position, &nCmdVelocity);
		/*
		if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_ANTI_SWAY)
		{
			Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_ABSOLUTE_POS, nControlWord_1.W, position, &nCmdVelocity);
		}
		else
		{
			Store_SRM_RxPDO_2(INV_FORK_1, OP_MODE_ABSOLUTE_POS, nControlWord_1.W, position, &nCmdVelocity);
		}
		*/

	}

	return M_CTR_ERROR_NONE;
}

// Manual Fork Position Control Test
// 리프트 위치제어로 테스트 코드 작성.
INT08U MANUAL_CTR_Fork(INT32S position, INT08U VelType)
{
	INT08U nInvertor = INV_FORK_1;

	UnitVelocitySTR nVelocity;

	ControlWord_A_t nControlWord;

	INT16U nOpMode = 0;
	MOVKIT_POS_Control_t nControlWord_1;

	nControlWord.W = 0;
	nControlWord_1.W = 0;

	memset((INT08U*)&nVelocity, 0, sizeof(UnitVelocitySTR));

	if ((m_SRM_Inverter_Error) || (Get_Inverter_Fault_State(nInvertor))) return M_CTR_ERROR_FALUT;

	if (Get_Inverter_Ready_State(nInvertor) == 0)	return M_CTR_ERROR_NOT_READY;

	if ((VelType == FORK_VEL_AUTO_H) || (VelType == FORK_VEL_AUTO_M) \
		|| (VelType == FORK_VEL_AUTO_L) \
		|| (VelType == FORK_VEL_AUTO_DEC_1) || (VelType == FORK_VEL_AUTO_DEC_2))
	{
		return M_CTR_ERROR_VELOCITY;
	}

	memcpy(&nVelocity, &m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));

	if ((m_ExtSEnv2.ForkDrive.ManualDrive.LeftPos != 0) \
		&& (m_ExtSEnv2.ForkDrive.ManualDrive.RightPos != 0))
	{
		if ((position < m_ExtSEnv2.ForkDrive.ManualDrive.LeftPos) \
			|| (position > m_ExtSEnv2.ForkDrive.ManualDrive.RightPos))
		{
			return M_CTR_ERROR_CMD_TARGET_POS;
		}
	}
	else
	{
		return M_CTR_ERROR_CMD_TARGET_POS;
	}

	/*
	if (Check_Lift_Software_Limit(position))
	{
		return M_CTR_ERROR_CMD_SOFT_LIMIT;;
	}
	*/

	if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
	{
		nControlWord.B.Mode = INV_MODE_AUTO;
		nControlWord.B.Enable_AppStop = 1;
		nControlWord.B.Enable_EmgStop = 1;
		nControlWord.B.Start = 1;
		Store_SRM_RxPDO(nInvertor, nControlWord.W, position, &nVelocity);
	}
	else
	{
		nControlWord_1.B.Enable_AppStop = 1;
		nControlWord_1.B.Enable_EmgStop = 1;
		nControlWord_1.B.Start = 1;

		Store_SRM_RxPDO_2(nInvertor, OP_MODE_ABSOLUTE_POS, nControlWord_1.W, position, &nVelocity);
		/*
		if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_ANTI_SWAY)
		{
			Store_SRM_RxPDO_2(nInvertor, OP_MODE_ABSOLUTE_POS, nControlWord_1.W, position, &nVelocity);
		}
		else
		{
			Store_SRM_RxPDO_2(nInvertor, OP_MODE_ABSOLUTE_POS, nControlWord_1.W, position, &nVelocity);
		}
		*/
	}

	return M_CTR_ERROR_NONE;
}

void Motor_Move_Stop(INT08U nInvertor, INT08U VelType)
{
	UnitVelocitySTR StopVelocity;
	ControlWord_A_t nControlWord;

	INT16U nOpMode = 0;
	MOVKIT_MAC_Control_t nControlWord_1;
	MOVKIT_POS_Control_t nControlWord_2;

	nControlWord.W = 0;
	nControlWord_1.W = 0;
	nControlWord_2.W = 0;

	memset((INT08U*)&StopVelocity, 0, sizeof(UnitVelocitySTR));

	if (nInvertor == INV_TRAVEL)
	{
		memcpy((INT08U*)&StopVelocity, (INT08U*)&m_ExtSEnv2.TravDrive.Vel[VelType], sizeof(UnitVelocitySTR));
	}
	else if (nInvertor == INV_HOIST)
	{
		memcpy((INT08U*)&StopVelocity, (INT08U*)&m_ExtSEnv2.LiftDrive.Vel[VelType], sizeof(UnitVelocitySTR));
	}
	else if (nInvertor == INV_FORK_1)
	{
		memcpy((INT08U*)&StopVelocity, (INT08U*)&m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));
	}

	StopVelocity.Acc = StopVelocity.Dec;
	StopVelocity.Spd = 0;

	if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
	{
		nControlWord.W = 0;
		nControlWord.B.Enable_AppStop = 1;
		nControlWord.B.Enable_EmgStop = 1;

		nControlWord.B.Start = 0;
		nControlWord.B.Mode = INV_MODE_AUTO;

		Store_SRM_RxPDO(nInvertor, nControlWord.W, 0, (UnitVelocitySTR*)&StopVelocity);
	}
	else if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_ANTI_SWAY)
	{
		if ((nInvertor == INV_TRAVEL) || (nInvertor == INV_HOIST))
		{
			nControlWord_1.W = 0;
			nControlWord_1.B.Enable_EmgStop = 1;
			nControlWord_1.B.Enable_AppStop = 1;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_1.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
		else if (nInvertor == INV_FORK_1)
		{
			nControlWord_2.W = 0;
			nControlWord_2.B.Enable_EmgStop = 1;
			nControlWord_2.B.Enable_AppStop = 1;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_2.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
	}
	else if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_SYNC_TRAVEL)
	{
		if ((nInvertor == INV_TRAVEL))
		{
			nControlWord_1.W = 0;
			nControlWord_1.B.Enable_EmgStop = 1;
			nControlWord_1.B.Enable_AppStop = 1;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_1.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
		else if ((nInvertor == INV_FORK_1) || (nInvertor == INV_HOIST))
		{
			nControlWord_2.W = 0;
			nControlWord_2.B.Enable_EmgStop = 1;
			nControlWord_2.B.Enable_AppStop = 1;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_2.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
	}
	else
	{
		nControlWord_2.W = 0;
		nControlWord_2.B.Enable_EmgStop = 1;
		nControlWord_2.B.Enable_AppStop = 1;

		Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_2.W, 0, (UnitVelocitySTR*)&StopVelocity);
	}
}

void Motor_Application_Stop(INT08U nInvertor, INT08U VelType)
{
	UnitVelocitySTR StopVelocity;
	ControlWord_A_t nControlWord;

	INT16U nOpMode = 0;
	MOVKIT_MAC_Control_t nControlWord_1;
	MOVKIT_POS_Control_t nControlWord_2;

	nControlWord.W = 0;
	nControlWord_1.W = 0;
	nControlWord_2.W = 0;

	memset((INT08U*)&StopVelocity, 0, sizeof(UnitVelocitySTR));

	if (nInvertor == INV_TRAVEL)
	{
		memcpy((INT08U*)&StopVelocity, (INT08U*)&m_ExtSEnv2.TravDrive.Vel[VelType], sizeof(UnitVelocitySTR));
	}
	else if (nInvertor == INV_HOIST)
	{
		memcpy((INT08U*)&StopVelocity, (INT08U*)&m_ExtSEnv2.LiftDrive.Vel[VelType], sizeof(UnitVelocitySTR));
	}
	else if (nInvertor == INV_FORK_1)
	{
		memcpy((INT08U*)&StopVelocity, (INT08U*)&m_ExtSEnv2.ForkDrive.Vel[VelType], sizeof(UnitVelocitySTR));
	}

	StopVelocity.Acc = StopVelocity.Dec;
	StopVelocity.Spd = 0;

	if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
	{
		nControlWord.W = 0;
		nControlWord.B.Enable_AppStop = 1;
		nControlWord.B.Enable_EmgStop = 0;

		//nControlWord.B.Start = 0;
		nControlWord.B.Mode = INV_MODE_AUTO;

		nControlWord.B.Start = 1;
		Store_SRM_RxPDO(nInvertor, nControlWord.W, 0, (UnitVelocitySTR*)&StopVelocity);
	}
	else if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_ANTI_SWAY)
	{
		nOpMode = OP_MODE_ABSOLUTE_POS;

		if ((nInvertor == INV_TRAVEL) || (nInvertor == INV_HOIST))
		{
			nControlWord_1.W = 0;
			nControlWord_1.B.Enable_EmgStop = 1;
			nControlWord_1.B.Enable_AppStop = 0;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_1.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
		else if (nInvertor == INV_FORK_1)
		{
			nControlWord_2.W = 0;
			nControlWord_2.B.Enable_EmgStop = 1;
			nControlWord_2.B.Enable_AppStop = 0;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_2.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
	}
	else if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_SYNC_TRAVEL)
	{
		nOpMode = OP_MODE_ABSOLUTE_POS;

		if ((nInvertor == INV_TRAVEL))
		{
			nControlWord_1.W = 0;
			nControlWord_1.B.Enable_EmgStop = 1;
			nControlWord_1.B.Enable_AppStop = 0;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_1.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
		else if ((nInvertor == INV_FORK_1) || (nInvertor == INV_HOIST))
		{
			nControlWord_2.W = 0;
			nControlWord_2.B.Enable_EmgStop = 1;
			nControlWord_2.B.Enable_AppStop = 0;

			Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_2.W, 0, (UnitVelocitySTR*)&StopVelocity);
		}
	}
	else
	{
		nOpMode = OP_MODE_ABSOLUTE_POS;

		nControlWord_2.W = 0;
		nControlWord_2.B.Enable_EmgStop = 1;
		nControlWord_2.B.Enable_AppStop = 0;

		Store_SRM_RxPDO_2(nInvertor, nOpMode, nControlWord_2.W, 0, (UnitVelocitySTR*)&StopVelocity);
	}
}

