void BE2LE_ModbusTxPDO(void)
{
	for (INT08U i = 0; i < INVERTOR_INSTALL_COUNT; i++)
	{
		m_SRM_TxPDO[i].StatusWord.W = swap_16U(m_Recv_TxPDO[i].StatusWord.W);
		m_SRM_TxPDO[i].CurPosition = swap_32U(m_Recv_TxPDO[i].CurPosition);
		m_SRM_TxPDO[i].ActualSpeed = swap_16U(m_Recv_TxPDO[i].ActualSpeed);
		m_SRM_TxPDO[i].ActualTorque = swap_16U(m_Recv_TxPDO[i].ActualTorque);
		m_SRM_TxPDO[i].ParamValueMSB = swap_16U(m_Recv_TxPDO[i].ParamValueMSB);
		m_SRM_TxPDO[i].ParamValueLSB = swap_16U(m_Recv_TxPDO[i].ParamValueLSB);
		m_SRM_TxPDO[i].ErrorMainCode = swap_32U(m_Recv_TxPDO[i].ErrorMainCode);
		m_SRM_TxPDO[i].ErrorSubCode = swap_16U(m_Recv_TxPDO[i].ErrorSubCode);
		m_SRM_TxPDO[i].FBErrorCode = swap_16U(m_Recv_TxPDO[i].FBErrorCode);
		m_SRM_TxPDO[i].ExternalEncoder = swap_16U(m_Recv_TxPDO[i].ExternalEncoder);
		m_SRM_TxPDO[i].Acutal_RefOffset = swap_32U(m_Recv_TxPDO[i].Acutal_RefOffset);
		m_SRM_TxPDO[i].Acutal_PosGain = swap_32U(m_Recv_TxPDO[i].Acutal_PosGain);
		m_SRM_TxPDO[i].Acutal_PosWindow = swap_16U(m_Recv_TxPDO[i].Acutal_PosWindow);
	}
}

