void HMI_Write_RealTime_Register(void)
{
	INT08U nWriteWordCnt = 0;
	INT16U nWriteAddress = HMI_ADDRESS_REALTIME + 3;

	INT16U nWriteData[200] = { 0, };
	INT16U i = 0;

	m_HMI_Com.Req_Flag = HMI_WRITE_REALTIME_REGISTER;

	nWriteWordCnt = (sizeof(HMI_RealTime_Register) - 6) >> 1;

	for (i = 0; i < nWriteWordCnt; i++)
	{
		nWriteData[i] = swap_16U(m_Send_HMI_Register.RealTime.Word[i + 3].W);
	}

	m_HMI_Com.Req_DataCount = nWriteWordCnt;
	m_HMI_Com.Recv_Flag = 0;

	ModbusTcpWrite(TCP_SOCKET_HMI, HMI_UNIT_ID, nWriteAddress, nWriteWordCnt, (INT16U*)nWriteData);

#if DEBUG_HMI_DEBUG
	//Set_TestStatus(DEBUG_STR_40, nWriteWordCnt);
#endif
}

void HMI_Read_RealTime_Register(void)
{
	INT08U nReadWordCnt = 0;

	m_HMI_Com.Req_Flag = HMI_READ_REALTIME_REGISTER;

	nReadWordCnt = sizeof(HMI_RealTime_Register) >> 1;

	m_HMI_Com.Req_DataCount = nReadWordCnt;
	m_HMI_Com.Recv_Flag = 0;

	ModbusTcpRead(TCP_SOCKET_HMI, HMI_UNIT_ID, HMI_ADDRESS_REALTIME, nReadWordCnt);

#if DEBUG_HMI_DEBUG
	//Set_TestStatus(DEBUG_STR_39, nReadWordCnt);
#endif
}

