void HMI_Write_RealTime_MW1(INT16U nData)
{
	INT08U nWriteWordCnt = 0;
	INT16U nWriteData = 0;
	INT16U nWriteAddress = HMI_ADDRESS_REALTIME + 1;

	static INT32U s_Send_Cnt = 0;

	++s_Send_Cnt;

	m_HMI_Com.Req_Flag = HMI_WRITE_REALTIME_MW1;

	nWriteWordCnt = 1;

	nWriteData = swap_16U(nData);

	m_HMI_Com.Req_DataCount = nWriteWordCnt;
	m_HMI_Com.Recv_Flag = 0;

	ModbusTcpWrite(TCP_SOCKET_HMI, HMI_UNIT_ID, nWriteAddress, nWriteWordCnt, (INT16U*)&nWriteData);
}

void HMI_Write_SystemTime_Register(INT08U nFlag)
{
	INT08U nWriteWordCnt = 0;
	INT16U nWriteAddress = HMI_ADDRESS_SYS_TIME_SET;

	INT16U nWriteData[4] = { 0, };
	INT16U i = 0;

	HMI_SystemData	nSystemData;

	m_HMI_Com.Req_Flag = HMI_WRITE_SYS_TIME;

	nWriteWordCnt = 4;

	memset((INT08U*)&nSystemData, 0, sizeof(HMI_SystemData));

	if (nFlag == 1)
	{
		nSystemData.Set_Year.Byte.Value = m_pgmEnv.Set_HMI_SysTime_Year;
		nSystemData.Set_Mon.W = m_pgmEnv.Set_HMI_SysTime_Mon;
		nSystemData.Set_Date.W = m_pgmEnv.Set_HMI_SysTime_Day;
		nSystemData.Set_Time.Byte.Hours = m_pgmEnv.Set_HMI_SysTime_Hour;
		nSystemData.Set_Time.Byte.Minutes = m_pgmEnv.Set_HMI_SysTime_Min;

		nSystemData.Set_Year.Byte.Flag = 1;

		
#if DEBUG_HMI_TIME
// 		Set_TestStatus(DEBUG_STR_60, nSystemData.Set_Year.Byte.Value);
// 		Set_TestStatus(DEBUG_STR_61, nSystemData.Set_Mon.W);
// 		Set_TestStatus(DEBUG_STR_62, nSystemData.Set_Date.W);
// 		Set_TestStatus(DEBUG_STR_63, nSystemData.Set_Time.Byte.Hours);
// 		Set_TestStatus(DEBUG_STR_64, nSystemData.Set_Time.Byte.Minutes);
		//Set_TestStatus(DEBUG_STR_60, nSystemData.Set_Year.Byte.Flag);
#endif
	}
	else
	{
		nSystemData.Set_Year.Byte.Value = m_pgmEnv.Set_HMI_SysTime_Year;
		nSystemData.Set_Mon.W = m_pgmEnv.Set_HMI_SysTime_Mon;
		nSystemData.Set_Date.W = m_pgmEnv.Set_HMI_SysTime_Day;
		nSystemData.Set_Time.Byte.Hours = m_pgmEnv.Set_HMI_SysTime_Hour;
		nSystemData.Set_Time.Byte.Minutes = m_pgmEnv.Set_HMI_SysTime_Min;

		nSystemData.Set_Year.Byte.Flag = 0;
	}

	nWriteData[0] = swap_16U(nSystemData.Set_Year.Word.W);
	nWriteData[1] = swap_16U(nSystemData.Set_Mon.W);
	nWriteData[2] = swap_16U(nSystemData.Set_Date.W);
	nWriteData[3] = swap_16U(nSystemData.Set_Time.Word.W);

	m_HMI_Com.Req_DataCount = nWriteWordCnt;
	m_HMI_Com.Recv_Flag = 0;

	ModbusTcpWrite(TCP_SOCKET_HMI, HMI_UNIT_ID, nWriteAddress, nWriteWordCnt, (INT16U*)nWriteData);
}

void RxModbusTcpData(INT08U nSocket, INT08U* data, INT16U len)
{
	INT16U ModbusRxPktTransactionID = 0;
	INT16U ModbusRxPktProtocolID = 0;
	INT16U ModbusRxPktLength = 0;
	INT08U ModbusRxPktUnitID = 0;

	INT08U ModbusRxPkt_FuncCode = 0;

	INT16U nRecvDataBuf[MAX_MODBUS_WORD_COUNT] = { 0, };

	static INT32U s_RecvCnt[10] = { 0, };

	if (len && (len <= sizeof(ModbusTcpSTR)))
	{
		modbus_rxlen = len;
		memcpy((INT08U*)&ModbusRxPkt, (INT08U*)data, len);
	}
	else
	{
		modbus_rxlen = 0;
	}

	if (modbus_rxlen)
	{
		ModbusRxPktTransactionID = swap_16U(ModbusRxPkt.TransactionID);
		ModbusRxPktProtocolID = swap_16U(ModbusRxPkt.ProtocolID);
		ModbusRxPktLength = swap_16U(ModbusRxPkt.Length);
		ModbusRxPktUnitID = swap_16U(ModbusRxPkt.UnitID);

		if (modbus_rxlen >= (ModbusRxPktLength + 6))
		{
#if DEBUG_MODBUS_SEW
			///*
			printf("[MODBUS_SEW] nSocket: %d, Rx TransactionID:%d ProtocolID:%d Length:%d UnitID:%d FunctionCode:0x%02x Length:%d\r\n",
				nSocket, ModbusRxPktTransactionID, ModbusRxPktProtocolID, ModbusRxPktLength, ModbusRxPktUnitID,
				ModbusRxPkt.FunctionCode, modbus_rxlen);
			//*/
#endif

			if (nSocket == 0)
			{
				if ((ModbusRxPktTransactionID == 0) && (ModbusRxPktProtocolID == 0) && (ModbusRxPktUnitID == 0))
				{
					if (modbus_rxlen == (ModbusRxPktLength + 6))
					{
						if (ModbusRxPkt.FunctionCode == FUNC_CODE_READ)
						{
							m_ModbusResponse[nSocket] = 1;

							/*
							if (ModbusRxPkt.FC03Resp.ByteCount == (sizeof(MoviC_TxPDO) * INVERTOR_INSTALL_COUNT))
							{

#if DEBUG_MODBUS_SEW
								printf("[MODBUS_SEW] nSocket: %d, Rx TransactionID:%d ProtocolID:%d Length:%d UnitID:%d FunctionCode:0x%02x Length:%d\r\n",
									nSocket, ModbusRxPktTransactionID, ModbusRxPktProtocolID, ModbusRxPktLength, ModbusRxPktUnitID,
									ModbusRxPkt.FunctionCode, modbus_rxlen);

								printf("[MODBUS_SEW] Rx FunctionCode:0x%02x ByteCount:%d\r\n",
									ModbusRxPkt.FunctionCode, ModbusRxPkt.FC03Resp.ByteCount);
#endif
								memcpy((INT08U*)&m_Recv_TxPDO, (INT08U*)&ModbusRxPkt.FC03Resp.Data[0], \
									(sizeof(MoviC_TxPDO) * INVERTOR_INSTALL_COUNT));

								BE2LE_ModbusTxPDO();
								Modbus_TxPDO_Update();
							}
							*/
						}
						else if (ModbusRxPkt.FunctionCode == FUNC_CODE_WRITE)
						{
							m_ModbusResponse[nSocket] = 2;

						}
						else if (ModbusRxPkt.FunctionCode == FUNC_CODE_WRITE_READ)
						{
							if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW)
							{
								if (ModbusRxPkt.FC23Resp.ByteCount == (sizeof(MoviC_TxPDO) * INVERTOR_INSTALL_COUNT))
								{
									m_ModbusResponse[nSocket] = 3;

									memcpy((INT08U*)&m_Recv_TxPDO, (INT08U*)&ModbusRxPkt.FC23Resp.Data[0], \
										(sizeof(MoviC_TxPDO) * INVERTOR_INSTALL_COUNT));

									m_St.SRM_Status1.Bit.InvertorConnect = 1;
									m_St.Inv_St[INV_TRAVEL].Status2.Connect = 1;
									m_St.Inv_St[INV_HOIST].Status2.Connect = 1;
									m_St.Inv_St[INV_FORK_1].Status2.Connect = 1;

									m_pgmEnv.Invertor_ComTimeOver = m_pgmEnv.timer1ms;

									BE2LE_ModbusTxPDO();
									Modbus_TxPDO_Update();
								}
							}
							else if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_ANTI_SWAY)
							{
								if (ModbusRxPkt.FC23Resp.ByteCount == (m_pgmEnv.Invertor_TxPDO_Size * 2))
								{
									m_ModbusResponse[nSocket] = 3;

									memcpy((INT08U*)&m_Recv_PI_Type_1, (INT08U*)&ModbusRxPkt.FC23Resp.Data[0], \
										(m_pgmEnv.Invertor_TxPDO_Size * 2));

									m_St.SRM_Status1.Bit.InvertorConnect = 1;
									m_St.Inv_St[INV_TRAVEL].Status2.Connect = 1;
									m_St.Inv_St[INV_HOIST].Status2.Connect = 1;
									m_St.Inv_St[INV_FORK_1].Status2.Connect = 1;

									m_pgmEnv.Invertor_ComTimeOver = m_pgmEnv.timer1ms;

									BE2LE_ModbusTxPDO_1();
									Modbus_TxPDO_Update_1();
								}
							}
							else if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2)
							{
								if (ModbusRxPkt.FC23Resp.ByteCount == (m_pgmEnv.Invertor_TxPDO_Size * 2))
								{
									m_ModbusResponse[nSocket] = 3;

									memcpy((INT08U*)&m_Recv_PI_Type_2, (INT08U*)&ModbusRxPkt.FC23Resp.Data[0], \
										(m_pgmEnv.Invertor_TxPDO_Size * 2));

									m_St.SRM_Status1.Bit.InvertorConnect = 1;
									m_St.Inv_St[INV_TRAVEL].Status2.Connect = 1;
									m_St.Inv_St[INV_HOIST].Status2.Connect = 1;
									m_St.Inv_St[INV_FORK_1].Status2.Connect = 1;

									m_pgmEnv.Invertor_ComTimeOver = m_pgmEnv.timer1ms;

									BE2LE_ModbusTxPDO_2();
									Modbus_TxPDO_Update_2();
								}
							}
							// 2025.10.09 Add to inpark 
							else if (m_ExtSEnv.Machine.mType.Inverter_Vendor == INV_VENDOR_SEW_VER2_SYNC_TRAVEL)
							{
								if (ModbusRxPkt.FC23Resp.ByteCount == (m_pgmEnv.Invertor_TxPDO_Size * 2))
								{
									m_ModbusResponse[nSocket] = 3;

									memcpy((INT08U*)&m_Recv_PI_Type_3, (INT08U*)&ModbusRxPkt.FC23Resp.Data[0], \
										(m_pgmEnv.Invertor_TxPDO_Size * 2));

									m_St.SRM_Status1.Bit.InvertorConnect = 1;
									m_St.Inv_St[INV_TRAVEL].Status2.Connect = 1;
									m_St.Inv_St[INV_HOIST].Status2.Connect = 1;
									m_St.Inv_St[INV_FORK_1].Status2.Connect = 1;

									m_pgmEnv.Invertor_ComTimeOver = m_pgmEnv.timer1ms;

									BE2LE_ModbusTxPDO_3();
									Modbus_TxPDO_Update_3();
								}
							}
						}
					}
					else
					{
						//m_TestStatus.St[22]++;
					}
				}
				else
				{
					//m_TestStatus.St[21]++;
				}
			}
			else if (nSocket == 1)
			{
#if DEBUG_MODBUS_HMI
				///*
				printf("[MODBUS_HMI] Rx nSocket: %d, Rx TransactionID:%d ProtocolID:%d Length:%d UnitID:%d FunctionCode:0x%02x Length:%d\r\n",
					nSocket, ModbusRxPktTransactionID, ModbusRxPktProtocolID, ModbusRxPktLength, ModbusRxPktUnitID,
					ModbusRxPkt.FunctionCode, modbus_rxlen);
				//*/
#endif
				++s_RecvCnt[5];


				//Set_TestStatus(DEBUG_STR_61, s_RecvCnt[5]);
	 			//Set_TestStatus(DEBUG_STR_62, ModbusRxPktLength);
	 			//Set_TestStatus(DEBUG_STR_63, modbus_rxlen);

				if ((ModbusRxPktTransactionID == 0) && (ModbusRxPktProtocolID == 0) && (ModbusRxPktUnitID == 0))
				{
					if (modbus_rxlen == (ModbusRxPktLength + 6))
					{
						//Set_TestStatus(DEBUG_STR_32, ModbusRxPkt.FunctionCode);

						if (ModbusRxPkt.FunctionCode >= 0x80)
						{
							ModbusRxPkt_FuncCode = ModbusRxPkt.FunctionCode - 0x80;
						}
						else
						{
							ModbusRxPkt_FuncCode = ModbusRxPkt.FunctionCode;
						}

						//Set_TestStatus(DEBUG_STR_63, ModbusRxPkt_FuncCode);

						if (ModbusRxPkt_FuncCode == FUNC_CODE_READ)
						{
#if DEBUG_MODBUS_HMI
							printf("[MODBUS_HMI] Rx FunctionCode:0x%02x ByteCount:%d\r\n",
								ModbusRxPkt_FuncCode, ModbusRxPkt.FC03Resp.ByteCount);
#endif

							if (m_HMI_Com.Req_Flag == HMI_READ_REALTIME_REGISTER)
							{
								++s_RecvCnt[0];
								m_HMI_Com.Recv_Flag = m_HMI_Com.Req_Flag;
#if DEBUG_HMI_DEBUG
								Set_TestStatus(DEBUG_STR_42, ModbusRxPkt.FC03Resp.ByteCount);
#endif
							}
							else if (m_HMI_Com.Req_Flag == HMI_READ_SYS_TIME)
							{
								++s_RecvCnt[7];
#if DEBUG_HMI_DEBUG
								Set_TestStatus(DEBUG_STR_44, ModbusRxPkt.FC03Resp.ByteCount);
#endif
							}
							else
							{
								++s_RecvCnt[6];
#if DEBUG_HMI_DEBUG
// 								Set_TestStatus(DEBUG_STR_49, ModbusRxPkt.FC03Resp.ByteCount);
// 								Set_TestStatus(DEBUG_STR_50, m_HMI_Com.Req_Flag);
#endif
							}

							memcpy((INT16U*)nRecvDataBuf, (INT16U*)&ModbusRxPkt.FC03Resp.Data[0], sizeof(INT08U) * ModbusRxPkt.FC03Resp.ByteCount);

#if DEBUG_HMI_DEBUG
 							Set_TestStatus(DEBUG_STR_41, ++s_RecvCnt[0]);
							Set_TestStatus(DEBUG_STR_43, ++s_RecvCnt[7]);
#endif

							BE2LE_HMI_TxPDO((INT16U*)&nRecvDataBuf, (ModbusRxPkt.FC03Resp.ByteCount >> 1));
						}
						else if (ModbusRxPkt_FuncCode == FUNC_CODE_WRITE)
						{
#if DEBUG_MODBUS_HMI
							printf("[MODBUS_HMI] Rx FunctionCode:0x%02x\r\n", ModbusRxPkt_FuncCode);
#endif
							if (m_HMI_Com.Req_Flag == HMI_WRITE_REALTIME_REGISTER)
							{
								++s_RecvCnt[1];
								m_HMI_Com.Recv_Flag = m_HMI_Com.Req_Flag;
							}
							else if (m_HMI_Com.Req_Flag == HMI_WRITE_REALTIME_MW1)
							{
								++s_RecvCnt[2];
								m_HMI_Com.Recv_Flag = m_HMI_Com.Req_Flag;
							}
							else if (m_HMI_Com.Req_Flag == HMI_WRITE_SYS_TIME)
							{
								++s_RecvCnt[4];
								m_HMI_Com.Recv_Flag = m_HMI_Com.Req_Flag;
							}
							else
							{
								++s_RecvCnt[3];
								m_HMI_Com.Recv_Flag = 0;
								//Set_TestStatus(DEBUG_STR_61, m_HMI_Com.Req_Flag);
							}

							m_ModbusResponse[nSocket] = 2;

						}
						else if (ModbusRxPkt_FuncCode == FUNC_CODE_WRITE_READ)
						{
							m_ModbusResponse[nSocket] = 3;
						}
					}
					else
					{
						NOP;
					}
				}
				else
				{
					NOP;
				}
			}
		}
		else if (modbus_rxlen)
		{
			//m_TestStatus.St[20]++;
		}
	}

//  	Set_TestStatus(DEBUG_STR_61, s_RecvCnt[0]);
//  	Set_TestStatus(DEBUG_STR_62, s_RecvCnt[1]);

	//Set_TestStatus(DEBUG_STR_62, s_RecvCnt[3]);
// 	Set_TestStatus(DEBUG_STR_63, s_RecvCnt[2]);
// 	Set_TestStatus(DEBUG_STR_64, s_RecvCnt[4]);
	/*
	Set_TestStatus(DEBUG_STR_46, s_RecvCnt[1]);
	Set_TestStatus(DEBUG_STR_48, s_RecvCnt[0]);
	Set_TestStatus(DEBUG_STR_50, s_RecvCnt[2]);
	Set_TestStatus(DEBUG_STR_51, s_RecvCnt[3]);
	*/
}

void ModbusTCP_Com_SEW_Ver1_Proc()
{
	INT08U i = 0;

	if (m_ExtSEnv.Machine.mType.Fork_Sensor_Type & cbits[0])
	{
		Fork1_Profile_Control_Proc();
	}

	for (i = 0; i < INVERTOR_INSTALL_COUNT; i++)
	{
		if (m_SRM_RxPDOQ[i].Front != m_SRM_RxPDOQ[i].Rear)
		{
			memcpy((INT08U*)&m_SRM_RxPDO[i], \
				(INT08U*)&m_SRM_RxPDOQ[i].Queue[m_SRM_RxPDOQ[i].Rear], sizeof(MoviC_RxPDO));

			if ((++m_SRM_RxPDOQ[i].Rear) >= MAX_SRM_RxPDO_Q_CNT)  m_SRM_RxPDOQ[i].Rear = 0;
		}
		else
		{
			memcpy((INT08U*)&m_SRM_RxPDO[i], \
				(INT08U*)&m_SRM_RxPDOQ[i].Last_RxPDO, sizeof(MoviC_RxPDO));
		}

		if (m_pgmEnv.Trial_Run_Mode)
		{
			// 시운전모드일 경우, HW Limit 사용 안함으로 설정
			m_SRM_RxPDO[i].ControlWord.B.DisableHW_Limit = 1;
		}

		if (m_St.SRM_Mode.Bit.Force)
		{
			m_SRM_RxPDO[i].ControlWord.B.DisableHW_Limit = 1;
		}
	}

	/*
	if (m_ExtSEnv.Machine.mType.Fork_Sensor_Type & cbits[0])
	{
		// 포크 로터리 엔코더 적용
		m_St.Inv_St[INV_FORK_1].Target_Pos = ForkProfile.TargetPos;
		m_St.Inv_St[INV_FORK_1].Target_Vel = (ForkProfile.target_velocity / 1000) * 60;
	}
	else
	{
		m_St.Inv_St[INV_FORK_1].Target_Pos = m_SRM_RxPDO[INV_FORK_1].TargetPosition;
		m_St.Inv_St[INV_FORK_1].Target_Vel = m_SRM_RxPDO[INV_FORK_1].Setpoint_Speed;
	}
	*/

	LE2BE_Modbus_RxPDO();
	ModbusTcpWriteRead_1(0, 4, m_pgmEnv.Invertor_RxPDO_Size, 4,
		m_pgmEnv.Invertor_TxPDO_Size, (INT16U*)&m_Send_RxPDO[0]);

}

void ModbusTCP_Com_SEW_Ver2_Proc1()
{
	static INT32U s_HandShake_Timer;
	static INT08U s_HandShakeIn = 0;

	//++m_TestStatus.Ctrl[DEBUG_CTR_2];

	if (m_SRM_PO_Que_1.Front != m_SRM_PO_Que_1.Rear)
	{
		memcpy((INT08U*)&m_SRM_PO_Type_1, &m_SRM_PO_Que_1.Buf[m_SRM_PO_Que_1.Rear], sizeof(MOVKIT_PO_TYPE_1));

		++m_SRM_PO_Que_1.Rear;
		if (m_SRM_PO_Que_1.Rear >= MAX_SRM_RxPDO_Q_CNT)
		{
			m_SRM_PO_Que_1.Rear = 0;
		}
	}
	else
	{
		memcpy((INT08U*)&m_SRM_PO_Type_1, &m_SRM_PO_Que_1.LastBuf, sizeof(MOVKIT_PO_TYPE_1));
	}

	/*
	if (getCalcTimer1ms(s_HandShake_Timer) > 500)
	{
		s_HandShakeIn ^= 0x01;

		m_SRM_PO_Type1.Hoist.ControlWord.B.HandshakeIn = s_HandShakeIn;
		m_SRM_PO_Type1.Travel.ControlWord.B.HandshakeIn = s_HandShakeIn;
		m_SRM_PO_Type1.Fork.ControlWord.B.HandshakeIn = s_HandShakeIn;

		s_HandShake_Timer = m_pgmEnv.timer1ms;
	}
	*/

	if (m_pgmEnv.Trial_Run_Mode || m_St.SRM_Mode.Bit.Force)
	{
		m_SRM_PO_Type_1.Hoist.ControlWord.B.Disable_limit_switch = 1;
		m_SRM_PO_Type_1.Travel.ControlWord.B.Disable_limit_switch = 1;
		m_SRM_PO_Type_1.Fork.ControlWord.B.Disable_limit_switch = 1;
	}
	else
	{
		m_SRM_PO_Type_1.Hoist.ControlWord.B.Disable_limit_switch = 0;
		m_SRM_PO_Type_1.Travel.ControlWord.B.Disable_limit_switch = 0;
		m_SRM_PO_Type_1.Fork.ControlWord.B.Disable_limit_switch = 0;
	}

	LE2BE_Modbus_RxPDO_1();
	ModbusTcpWriteRead_1(0, 0, m_pgmEnv.Invertor_RxPDO_Size, 0,
		m_pgmEnv.Invertor_TxPDO_Size, (INT16U*)&m_Send_PO_Type_1.W);
}

