INT16S Lift_Position_Binary_Search_Left(INT16U nMaxCount, INT32S nPostion)
{
	INT32S nPoint_Diff_0 = 0;
	INT32S nPoint_Diff_1 = 0;

	INT32S nPoint_upper = 0;
	INT32S nPoint_lower = 0;

	INT16S nFirst_Point = 0;
	//INT16S nEnd_Point = nMaxCount - 1;
	INT16S nEnd_Point = nMaxCount - 1;
	INT16S nMid_Point = 0;

	if (nPostion < m_pgmEnv.PosSeq_Y_Left[0])	return -1;

	if (Check_Available_Lift_InPostion_Tolerance())
	{
		// [1] : 수동운전 시작위치
		// [2] : 레벨 정위치 시작
		if (nPostion < (m_pgmEnv.PosSeq_Y_Left[1] + m_ExtSEnv2.LiftDrive.InPos_Tolerance))
			return nFirst_Point;

		// 
		if (nPostion > (m_pgmEnv.PosSeq_Y_Left[nEnd_Point - 1] - m_ExtSEnv2.LiftDrive.InPos_Tolerance))
			return nEnd_Point;
	}
	else
	{
		if (nPostion < (m_pgmEnv.PosSeq_Y_Left[2] - DEF_LIFT_IN_POS_OFFSET))
			return nFirst_Point;

		if (nPostion > (m_pgmEnv.PosSeq_Y_Left[nEnd_Point - 1] - DEF_LIFT_IN_POS_OFFSET))
			return nEnd_Point;
	}

	nFirst_Point += 1;
	nEnd_Point -= 1;

	while (nFirst_Point <= nEnd_Point)
	{
		nMid_Point = (nFirst_Point + nEnd_Point) >> 1;

		nPoint_Diff_0 = (m_pgmEnv.PosSeq_Y_Left[nMid_Point + 1] - m_pgmEnv.PosSeq_Y_Left[nMid_Point]) >> 1;
		nPoint_Diff_1 = (m_pgmEnv.PosSeq_Y_Left[nMid_Point] - m_pgmEnv.PosSeq_Y_Left[nMid_Point - 1]) >> 1;

		nPoint_upper = (INT32S)m_pgmEnv.PosSeq_Y_Left[nMid_Point] + nPoint_Diff_0;
		nPoint_lower = (INT32S)m_pgmEnv.PosSeq_Y_Left[nMid_Point] - nPoint_Diff_1;
		/*
		if (Check_Available_Lift_InPostion_Tolerance())
		{
			nPoint_upper = (INT32S)m_pgmEnv.PosSeq_Y_Left[nMid_Point] + nPoint_Diff_0 + m_ExtSEnv2.LiftDrive.InPos_Tolerance;
			nPoint_lower = (INT32S)m_pgmEnv.PosSeq_Y_Left[nMid_Point] - nPoint_Diff_1 - m_ExtSEnv2.LiftDrive.InPos_Tolerance;
		}
		else
		{
			nPoint_upper = (INT32S)m_pgmEnv.PosSeq_Y_Left[nMid_Point] + nPoint_Diff_0 + DEF_LIFT_IN_POS_OFFSET;
			nPoint_lower = (INT32S)m_pgmEnv.PosSeq_Y_Left[nMid_Point] - nPoint_Diff_1 - DEF_LIFT_IN_POS_OFFSET;
		}
		*/

		nPoint_upper += m_ExtSEnv2.LiftDrive.LevelUpOffset;
		nPoint_lower += m_ExtSEnv2.LiftDrive.LevelDnOffset;

		if ((nPostion <= nPoint_upper) && (nPostion >= nPoint_lower))
		{
			return nMid_Point + 1;
		}
		else if (nPostion < nPoint_lower)
		{
			nEnd_Point = nMid_Point - 1;
		}
		else if (nPostion > nPoint_upper)
		{
			nFirst_Point = nMid_Point + 1;
		}
	}

	return -1;
}

