INT32S Get_Rack_Lift_Position_Dir(INT08U nFeeding, INT08U nPosFlag, INT16U nLevelNo)
{
	INT32S nPosition = 0;

	if ((nLevelNo > 0) && (nLevelNo <= MAX_LEVEL_COUNT))		// 1 ~ 128
	{
		if (nLevelNo <= m_ExtSEnv0.RackConfig.LvCount)
		{
			if ((nPosFlag == MOVE_POSITION_FORK1_L) || (nPosFlag == MOVE_POSITION_FORK2_L))
			{
				// RACK_LEFT
				//if (Is_Exist_Goods(nFeeding))
				if (m_St.Inv_St[INV_FORK_1].Status1.GoodsFlag_Or_MoveHome)
				{
					// Lift upper position
					nPosition = m_ExtSEnv0.CellConfig_Left.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelUpOffset;
				}
				else
				{
					// Lift lower position
					nPosition = m_ExtSEnv0.CellConfig_Left.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelDnOffset;
				}
			}
			else
			{
				// RACK_RIGHT
				//if (Is_Exist_Goods(nFeeding))
				if (m_St.Inv_St[INV_FORK_1].Status1.GoodsFlag_Or_MoveHome)
				{
					// Lift upper position
					nPosition = m_ExtSEnv0.CellConfig_Right.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelUpOffset;
				}
				else
				{
					// Lift lower position
					nPosition = m_ExtSEnv0.CellConfig_Right.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelDnOffset;
				}
			}
		}
	}

	return nPosition;
}

INT32S Get_Rack_ForkOut_Lift_Position(INT08U nPosFlag, INT16U nLevelNo, INT08U nGoodFlag)
{
	INT32S nPosition = 0;

	if ((nLevelNo > 0) && (nLevelNo <= MAX_LEVEL_COUNT))		// 1 ~ 128
	{
		if (nLevelNo <= m_ExtSEnv0.RackConfig.LvCount)
		{
			if (1/*m_ExtSEnv.Machine.mType.Fork_Type == FORK_TYPE_SINGLE_DEEP*/)
			{
				if ((nPosFlag == MOVE_POSITION_FORK1_L) || (nPosFlag == MOVE_POSITION_FORK2_L))
				{
					if (nGoodFlag)
					{
						// Lift upper position
						nPosition = m_ExtSEnv0.CellConfig_Left.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelUpOffset;
					}
					else
					{
						// Lift lower position
						nPosition = m_ExtSEnv0.CellConfig_Left.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelDnOffset;
					}
				}
				else
				{
					if (nGoodFlag)
					{
						// Lift upper position
						nPosition = m_ExtSEnv0.CellConfig_Right.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelUpOffset;
					}
					else
					{
						// Lift lower position
						nPosition = m_ExtSEnv0.CellConfig_Right.LvPos[nLevelNo - 1] + m_ExtSEnv2.LiftDrive.LevelDnOffset;
					}
				}
			}
		}
	}

	return nPosition;
}

