INT08U Check_Order_Prohibit_Rack(INT08U OrderCode, ForkWorkCmdSTR* ForkWorkCmd)
{
	INT08U Result = 0;
	INT08U chk_field = 0;

	if (!m_ExtSEnv1.ProhibitRack.Count)		return 0;

	// bit0:from_cell, bit1:to_cell

	switch (OrderCode)
	{
	case ORDER_CODE_RACK_CHG_DST:
		//case ORDER_CODE_STICKY:
			//case ORDER_CODE_STATION_CHG_DST:
				// 스테이션은 금지랙 확인 안함.
		chk_field = 0x02;
		break;

	case ORDER_CODE_STORE:
	case ORDER_CODE_UNSTORE:
	case ORDER_CODE_RACK_TO_RACK:
		//case ORDER_CODE_STATION_TO_STATION:
			// 스테이션은 금지랙 확인 안함.
		chk_field = 0x03;
		break;

	case ORDER_CODE_STICKY:
		// From 위치값으로 처리
		chk_field = 0x01;
		/*
		if ((ForkWorkCmd->FromCell.Row_ID != 0) &&
			(ForkWorkCmd->FromCell.Bay_ID != 0) &&
			(ForkWorkCmd->FromCell.Level_ID != 0))
		{
			// From 위치값으로 처리
			chk_field = 0x01;
		}
		else
		{
			// To 위치값으로 처리
			chk_field = 0x02;
		}
		*/
		break;

	case ORDER_CODE_NONE:
	default:
		chk_field = 0x00;
		break;
	}

	if (chk_field & 0x01)
	{
		if (Check_Prohibit_Rack(&ForkWorkCmd->FromCell))
		{
			Result |= cbits[0];
		}
		//Result = Check_Prohibit_Rack(&ForkWorkCmd->FromCell);
	}

	if (chk_field & 0x02)
	{
		if (Check_Prohibit_Rack(&ForkWorkCmd->ToCell))
		{
			Result |= cbits[1];
		}
		//Result = Check_Prohibit_Rack(&ForkWorkCmd->ToCell);
	}

	return Result;
}

