INT08U Check_Task_Prohibit_Rack(INT08U nTaskCmd, CellPosSTR* pCellPos)
{
	INT08U Result = 0;
	//INT08U chk_field = 0;
	//INT08U i = 0;
	//INT08U nChkCount = 0;
	//INT08U row = 0, bay = 0, lvl = 0;

	if (!m_ExtSEnv1.ProhibitRack.Count)		return 0;

	//nChkCount = m_ExtSEnv1.ProhibitRack.Count;

	if ((pCellPos->Row_ID == 0) && (pCellPos->Level_ID == 0) && (pCellPos->Bay_ID == 0))
	{
		asm volatile("NOP");
	}
	else
	{
		if (nTaskCmd != 0x01)
		{
			// Loading, Unloading 일 경우만 확인
			Result = Check_Prohibit_Rack(pCellPos);
		}
	}

	return Result;
}

INT08U Check_Special_Rack(CellPosSTR* ptrCell, INT08U nCmdGoodsType)
{
	INT08U Result = 0;
	INT08U i = 0, j = 0;
	INT08U row = 0, bay = 0, lvl = 0, GoodType = 0;
	INT08U nChkCount = 0;

	nChkCount = m_ExtSEnv1.SpecialRack.Count;

	if (nChkCount > 0)
	{
		for (i = 0; i < nChkCount; i++)
		{
			row = m_ExtSEnv1.SpecialRack.SetData[i].Row_No;
			bay = m_ExtSEnv1.SpecialRack.SetData[i].Bay_No;
			lvl = m_ExtSEnv1.SpecialRack.SetData[i].Lv_No;
			GoodType = m_ExtSEnv1.SpecialRack.SetData[i].Goods_Type;

			if ((row == 0) && (bay == 0) && (lvl == 0))
			{
				asm volatile("NOP");
			}
			else
			{
				if (((bay == ptrCell->Bay_ID) && (lvl == ptrCell->Level_ID))
					|| ((bay == ptrCell->Bay_ID) && (lvl == 0))
					|| ((bay == 0) && (lvl == ptrCell->Level_ID))
					|| ((bay == 0) && (lvl == 0)))
				{
					for (j = 0; j < 4; j++)
					{
						if (row & cbits[j])
						{
							if (ptrCell->Row_ID == (j + 1))
							{
								if (GoodType)
								{
									if (GoodType & nCmdGoodsType)
									{
										Result = 0;
									}
									else
									{
										Result = 1;
									}
								}
								else
								{
									Result = 1;
								}
							}
						}
					}
				}
			}
		}
	}

	return Result;
}


INT08U Check_Order_Special_Rack(INT08U OrderCode, ForkWorkCmdSTR* ForkWorkCmd)
{
	INT08U Result = 0;
	INT08U chk_field = 0;
	//INT08U i = 0;
	//INT08U nChkCount = 0;
	//INT08U row = 0, bay = 0, lvl = 0;

	if (!m_ExtSEnv1.SpecialRack.Count)		return 0;

	// bit0:from_cell, bit1:to_cell
	switch (OrderCode)
	{
	case ORDER_CODE_RACK_CHG_DST:
		//case ORDER_CODE_STICKY:
			//case ORDER_CODE_STATION_CHG_DST:
		chk_field = 0x02;
		break;

	case ORDER_CODE_STORE:
	case ORDER_CODE_UNSTORE:
	case ORDER_CODE_RACK_TO_RACK:
		//case ORDER_CODE_STATION_TO_STATION:
		chk_field = 0x03;
		break;

	case ORDER_CODE_NONE:
	case ORDER_CODE_STICKY:
	default:
		chk_field = 0x00;
		break;
	}

	//nChkCount = m_ExtSEnv1.SpecialRack.Count;

	if (chk_field & 0x01)
	{
		// 화물 적재 후, 화물타입을 알 수 있음. 반송지령 수신시에는 체크하지 않음 <-

		if (Check_Special_Rack(&ForkWorkCmd->FromCell, ForkWorkCmd->Good_Type))
		{
			Result |= cbits[0];
		}
		//Result = Check_Special_Rack(&ForkWorkCmd->FromCell, ForkWorkCmd->Good_Type);
	}

	if (chk_field & 0x02)
	{
		if (Check_Special_Rack(&ForkWorkCmd->ToCell, ForkWorkCmd->Good_Type))
		{
			Result |= cbits[1];
		}
		//Result = Check_Special_Rack(&ForkWorkCmd->ToCell, ForkWorkCmd->Good_Type);
	}

	return Result;
}

INT08U Check_Task_Special_Rack(INT08U nTaskCmd, CellPosSTR* pCellPos, INT08U nGoodType)
{
	INT08U Result = 0;

	if (!m_ExtSEnv1.SpecialRack.Count)		return 0;

	if ((pCellPos->Row_ID == 0) && (pCellPos->Level_ID == 0) && (pCellPos->Bay_ID == 0))
	{
		asm volatile("NOP");
	}
	else
	{
		if (nTaskCmd != 0x01)
		{
			Result = Check_Special_Rack(pCellPos, nGoodType);
		}
	}

	return Result;
}

void Update_Operation_Info_Time(INT08U nItem, INT32U nOperationTime_ms)
{
	INT32U nCalc_Sec = 0;
	INT32U nCalc_Sum_Minute = 0;

	if (nItem < 4)
	{
		// 0xFFFFFFFF 초 = 4294967295 초 = 약 136.2년
		if (m_BKSram.OperationInfo.Operation_Time[nItem].Sum_Second < 0xFFFFFFFF)
		{
			nCalc_Sec = nOperationTime_ms / 1000;

			m_BKSram.OperationInfo.Operation_Time[nItem].Sum_Second += nCalc_Sec;

			nCalc_Sum_Minute = (m_BKSram.OperationInfo.Operation_Time[nItem].Sum_Second + 30) / 60;
			m_BKSram.OperationInfo.Operation_Time[nItem].Sum_Minute = nCalc_Sum_Minute;

			saveBKSramBlock((INT08U*)&m_BKSram.OperationInfo.Operation_Time[nItem], sizeof(SumOperateTimeSTR));
		}
	}
}

void Update_Operation_Info_Distance(INT08U nItem, INT32U nOperDistance_mm)
{
	INT32U nCalc_Moving_Distance_Meter = 0;

	if (nItem < 4)
	{
		if (m_BKSram.OperationInfo.Moving_Distance[nItem].Sum_Meter < 0xFFFFFFFF)
		{
			m_BKSram.OperationInfo.Moving_Distance[nItem].Sum_mm += nOperDistance_mm;

			nCalc_Moving_Distance_Meter = (m_BKSram.OperationInfo.Moving_Distance[nItem].Sum_mm + 500) / 1000;
			m_BKSram.OperationInfo.Moving_Distance[nItem].Sum_Meter = nCalc_Moving_Distance_Meter;

			saveBKSramBlock((INT08U*)&m_BKSram.OperationInfo.Moving_Distance[nItem], sizeof(SumDistanceSTR));
		}
	}
}

void Update_BrakeOpen_CountUp(INT08U nInvertor)
{
	if (m_BKSram.OperationInfo.BrakeOpen_Count[nInvertor] < 0xFFFFFFFF)
	{
		++m_BKSram.OperationInfo.BrakeOpen_Count[nInvertor];
		saveBKSramBlock((INT08U*)&m_BKSram.OperationInfo.BrakeOpen_Count[nInvertor], sizeof(INT32U));
	}
}

INT32U Read_DelayTime(INT08U nForkAct, INT08U nTimerIndex)
{
	INT32U nReadTimer = 0;

	if (nForkAct == WORK_FORK1_GET)
	{
		if (m_ExtSEnv2.CtrParam.Loading_Delay.mSetValue[nTimerIndex])
		{
			nReadTimer = m_ExtSEnv2.CtrParam.Loading_Delay.mSetValue[nTimerIndex] * 10; // 0.01 -> ms
		}
	}
	else if (nForkAct == WORK_FORK1_PUT)
	{
		if (m_ExtSEnv2.CtrParam.Unloading_Delay.mSetValue[nTimerIndex])
		{
			nReadTimer = m_ExtSEnv2.CtrParam.Unloading_Delay.mSetValue[nTimerIndex] * 10; // 0.01 -> ms
		}
	}
	else
	{
		if (m_St.Inv_St[INV_FORK_1].Status1.GoodsFlag_Or_MoveHome)
		{
			if (m_ExtSEnv2.CtrParam.Unloading_Delay.mSetValue[nTimerIndex])
			{
				nReadTimer = m_ExtSEnv2.CtrParam.Unloading_Delay.mSetValue[nTimerIndex] * 10; // 0.01 -> ms
			}

		}
		else
		{
			if (m_ExtSEnv2.CtrParam.Loading_Delay.mSetValue[nTimerIndex])
			{
				nReadTimer = m_ExtSEnv2.CtrParam.Loading_Delay.mSetValue[nTimerIndex] * 10; // 0.01 -> ms
			}
		}
	}

	if (nReadTimer == 0)
	{
		if (nTimerIndex == DELAY_PREFORE_MOVE)
		{
			nReadTimer = DEF_DELAY_BEFORE_MOVE;
		}
		else if (nTimerIndex == DELAY_AFTER_MOVE)
		{
			nReadTimer = DEF_DELAY_AFTER_MOVE;
		}
		else if (nTimerIndex == DELAY_BEFORE_FORK_OUT_LIFT)
		{
			nReadTimer = DEF_DELAY_PRE_FK_LIFT_GET;
		}
		else if (nTimerIndex == DELAY_AFTER_FORK_OUT_LIFT)
		{
			nReadTimer = DEF_DELAY_FK_LIFT_GET;
		}
		/*
		else if (nTimerIndex == DELAY_BEFORE_FORK_OUT)
		{
			nReadTimer = DEF_DELAY_PRE_FORK_OUT_GET;
		}

		else if (nTimerIndex == DELAY_AFTER_FORK_OUT)
		{
			nReadTimer = DEF_DELAY_FORK_OUT_GET;
		}
		else if (nTimerIndex == DELAY_BEFORE_FORK_CENTER)
		{
			nReadTimer = DEF_DELAY_PRE_FK_IN_GET;
		}
		else if (nTimerIndex == DELAY_AFTER_FORK_CENTER)
		{
			nReadTimer = DEF_DELAY_FK_IN_GET;
		}
		else
		{
			nReadTimer = 1500;
		}
		*/
	}
	else
	{
		if (nTimerIndex == DELAY_AFTER_MOVE)
		{
			// 이동 후, 최소 지연시간 500으로 변경.
			// 동일위치에서 작업 시, 정위치 정지 이상이 발생할 수 있음.
			if (nReadTimer < DEF_DELAY_AFTER_MOVE)
			{
				nReadTimer = DEF_DELAY_AFTER_MOVE;
			}

			//m_TestStatus.St[DEBUG_STR_25] = nReadTimer;
		}
	}

	return nReadTimer;
}


INT32U Get_Stabilzation_Time(SRM_WorkDataSTR* pWorkData)
{
	INT32U nStabilzationTime = 0;

	INT08U i = 0;
	INT08U nStationNO = 0;

	INT08U nCount = m_ExtSEnv2.CtrParam.Stabilzation_TimeSet.CaseCount;
	INT08U nLevelNO = 0;

	if (pWorkData->ForkAct != WORK_MOVE_ONLY)
	{
		if (pWorkData->Station_No > 0)
		{
			if (m_ExtSEnv1.StationEnv.TotalUseCnt > 0)
			{
				nStationNO = pWorkData->Station_No - 1;

				nStabilzationTime = m_ExtSEnv1.StationEnv.StationSet[nStationNO].Stabilzation_Time * 100;	// 1 = 100ms, 0.1초 -> ms
			}
		}
		else
		{
			if (nCount > 0)
			{
				nLevelNO = pWorkData->TargetPos.Level_ID;

				if (nLevelNO > 0)
				{
					for (i = 0; i < nCount; i++)
					{
						if ((m_ExtSEnv2.CtrParam.Stabilzation_TimeSet.mSetting[i].StartLevel <= nLevelNO) \
							&& (m_ExtSEnv2.CtrParam.Stabilzation_TimeSet.mSetting[i].EndLevel >= nLevelNO))
						{
							nStabilzationTime = m_ExtSEnv2.CtrParam.Stabilzation_TimeSet.mSetting[i].Time * 100; // 1 = 100ms, 0.1초 -> ms
							break;
						}
					}
				}
			}
		}
	}

	return nStabilzationTime;
}

INT32U Get_OverTime_Auto(INT08U nTimerIndex)
{
	INT32U nReadTimer = 0;

	if (m_ExtSEnv2.CtrParam.AutoTimeout.mSetValue[nTimerIndex])
	{
		nReadTimer = m_ExtSEnv2.CtrParam.AutoTimeout.mSetValue[nTimerIndex] * 10; // 0.01 -> ms
	}

	if (nReadTimer == 0)
	{
		if (nTimerIndex == AUTO_TIMEOUT_MOVE_TRAV_LIFT)
		{
			// 0 : 무한대기
			//nReadTimer = DEF_TIMEOUT_MOVE;
		}
		else if (nTimerIndex == AUTO_TIMEOUT_MOVE_FORK_OUT)
		{
			nReadTimer = DEF_TIMEOUT_FORK_MOVE;
		}
		else if (nTimerIndex == AUTO_TIMEOUT_MOVE_FORK_OUT_LIFT)
		{
			nReadTimer = DEF_TIMEOUT_FORK_OUT_LIFT;
		}
		else if (nTimerIndex == AUTO_TIMEOUT_MOVE_FORK_CENTER)
		{
			nReadTimer = DEF_TIMEOUT_FK_CENTER;
		}
		else if (nTimerIndex == AUTO_TIMEOUT_DETECT_GOODS)
		{
			nReadTimer = DEF_TIMEOUT_CHK_GOX;
		}
		else if (nTimerIndex == AUTO_TIMEOUT_WAIT_INTERLOCK)
		{
			nReadTimer = DEF_TIMEOUT_WAIT_INTERLOCK;
		}
		else
		{
			nReadTimer = 20000;
		}
	}

	return nReadTimer;
}

INT32U Get_OverTime_Drive(INT08U nTimerIndex)
{
	INT32U nReadTimer = 0;

	if (m_ExtSEnv2.CtrParam.DrvTimeout.SetValue[nTimerIndex])
	{
		nReadTimer = m_ExtSEnv2.CtrParam.DrvTimeout.SetValue[nTimerIndex] * 10; // 0.01 -> ms
	}

	if (nReadTimer == 0)
	{
		if (nTimerIndex == DRIVE_TIMEOUT_MANUAL_RXCOM)
		{
			nReadTimer = 1500;
		}
		else if (nTimerIndex == DRIVE_TIMEOUT_HOME_RETURN)
		{
			nReadTimer = DEF_TIMEOUT_MOVE;
		}
		else
		{
			nReadTimer = 20000;
		}
	}

	return nReadTimer;
}

