/**
  * @brief
  * @param None
  * @retval None
  */
void Travel_Setup_Move_Position()
{
	static INT32U s_OperationTime = 0;

	static INT32U s_SeqTimer = 0;
	static INT32U s_CheckTimer = 0;

	INT08U nFlag = 0;
	INT08U nDef_Move_Speed = TRAV_VEL_MAN_M;

	INT32S nUpperPos = 0;
	INT32S nLowerPos = 0;

	INT08U nTrav_Control_Error = 0;

	static INT32S s_Move_TargetPos = 0;

	INT08U i = 0;

	if (Check_SRM_Error_State() || (Get_Inverter_Fault_State(INV_TRAVEL)))
	{
		m_SRM_Sub_RunStep_0 = 100;
	}

	if (m_pgmEnv.NormalStopFlag)
	{
		m_pgmEnv.NormalStopFlag = 0;

		m_SRM_Sub_RunStep_0 = 10;
	}

	if (m_pgmEnv.EmergencyStopFlag)
	{
		m_pgmEnv.EmergencyStopFlag = 0;

		SetTimer1ms(&s_SeqTimer);
		Motor_Emergency_Stop(INV_TRAVEL);

		m_SRM_Sub_RunStep_0 = 11;
	}

	switch (m_SRM_Sub_RunStep_0)
	{
	case 0:
		break;

	case 1:
		nFlag = Check_Fork_Center_Alarm();
		if (nFlag)
		{
			m_SRM_Sub_RunStep_0 = 100;
		}
		else
		{
			if (m_St.Inv_St[INV_TRAVEL].Status2.IPOS_ref)
			{
				if (m_ExtSEnv2.TravDrive.ManualDrive.StartPos \
					&& m_ExtSEnv2.TravDrive.ManualDrive.EndPos)
				{
					nUpperPos = m_ExtSEnv2.TravDrive.ManualDrive.EndPos + m_ExtSEnv2.TravDrive.InPos_Tolerance;
					nLowerPos = m_ExtSEnv2.TravDrive.ManualDrive.StartPos - m_ExtSEnv2.TravDrive.InPos_Tolerance;

					//m_TestStatus.St[DEBUG_STR_6] = nUpperPos;
					//m_TestStatus.St[DEBUG_STR_7] = nLowerPos;

					// Start Move
					if ((m_pgmEnv.Setup_Target_Pos[INV_TRAVEL] <= nUpperPos) \
						&& (m_pgmEnv.Setup_Target_Pos[INV_TRAVEL] >= nLowerPos))
					{
						m_pgmEnv.Buzzer_OneShot = 1;

						m_pgmEnv.Enable_Setup_Move_Position_Timer = m_pgmEnv.timer1ms;

						SetTimer1ms(&s_SeqTimer);
						m_SRM_Sub_RunStep_0 = 2;
					}
					else
					{
						Event_Warning_Code(WARNING_CODE_60, 0, 0);
						m_SRM_Sub_RunStep_0 = 100;
					}
				}
				else
				{
					Event_Warning_Code(WARNING_CODE_60, 1, 0);
					m_SRM_Sub_RunStep_0 = 100;
				}
			}
			else
			{
				Event_Warning_Code(WARNING_CODE_60, 2, 0);
				m_SRM_Sub_RunStep_0 = 100;
			}
		}
		break;

	case 2:
		s_Move_TargetPos = m_pgmEnv.Setup_Target_Pos[INV_TRAVEL];
		nTrav_Control_Error = Auto_Ctr_Travel(s_Move_TargetPos, nDef_Move_Speed);

		if (nTrav_Control_Error)
		{
			save_error_code(ERROR1_INVERTER_TRAVEL, 4, nTrav_Control_Error);

			m_SRM_Sub_RunStep_0 = 100;
		}
		else
		{
			SetTimer1ms(&s_SeqTimer);
			m_SRM_Sub_RunStep_0 = 3;
		}
		break;

	case 3:
		if (getCalcTimer1ms(s_SeqTimer) > 500)
		{
			SetTimer1ms(&s_SeqTimer);

			if (check_inverter_In_position_reach(INV_TRAVEL, s_Move_TargetPos))
			{
				SetTimer1ms(&s_SeqTimer);
				m_SRM_Sub_RunStep_0 = 5;
			}
		}
		break;

	case 5:
		if (getCalcTimer1ms(s_SeqTimer) > 1000)
		{
			Motor_Application_Stop(INV_TRAVEL, TRAV_VEL_MAN_M);

			SetTimer1ms(&s_SeqTimer);
			m_SRM_Sub_RunStep_0 = 50;
		}
		break;

	case 10:
		Motor_Move_Stop(INV_TRAVEL, TRAV_VEL_MAN_M);

		SetTimer1ms(&s_SeqTimer);
		m_SRM_Sub_RunStep_0 = 11;
		break;

	case 11:
		if (getCalcTimer1ms(s_SeqTimer) > 1000)
		{
			if ((Get_Inverter_Motor_Turning(INV_TRAVEL) == 0) \
				&& (Get_Inverter_Actual_Speed(INV_TRAVEL) == 0))
			{
				m_SRM_Sub_RunStep_0 = 5;
			}
		}
		break;

	case 50:
		break;

	case 100:
		break;
	}

	///*
	//m_TestStatus.St[DEBUG_STR_5] = m_SRM_Sub_RunStep_0;
	//m_TestStatus.St[DEBUG_STR_6] = s_Move_TargetPos;
	//*/
	//memcpy((INT32S*)&m_TestStatus.St[DEBUG_STR_10], s_Move_Forward_SenPos, sizeof(INT32S) * 8);
	//memcpy((INT32S*)&m_TestStatus.St[DEBUG_STR_18], s_Move_Reverse_SenPos, sizeof(INT32S) * 8);
}

