INT08U Get_Station_Interlock_CVNO_State(INT08U nStatinNo)
{
	INT08U nInterLock_No = 0;
	INT08U nByte_Index = 0;
	INT08U nBit_Index = 0;

	INT08U nState = 0;

	nInterLock_No = (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No - 1);

	if (m_ExtSEnv1.StationEnv.InterLock_Type == 1)
	{
		if (nInterLock_No <= 7)
		{
			if (Get_DO_State(OUT_CVNO1 + nInterLock_No))
			{
				nState = 1;
			}
			else
			{
				nState = 0;
			}
		}
	}
	else if (m_ExtSEnv1.StationEnv.InterLock_Type == 2)
	{
		if (nInterLock_No <= 49)
		{
			nByte_Index = nInterLock_No / 8;
			nBit_Index = nInterLock_No % 8;

			if (m_St.InterLock_CVNO[nByte_Index] & cbits[nByte_Index])
			{
				nState = 1;
			}
			else
			{
				nState = 0;
			}
		}
	}

	return nState;
}

void Clear_Station_Interlock_Contol()
{
	INT08U i = 0;

	for (i = 0; i < 8; i++)
	{
		DO_Control((OUT_CVNO1 + i), 0);
	}
}

void Station_Interlock_Control(INT08U nStatinNo, INT08U nFlag)
{
	INT08U nInterLock_No = 0;
	INT08U nByte_Index = 0;
	INT08U nBit_Index = 0;

	nInterLock_No = (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No - 1);

	if (m_ExtSEnv1.StationEnv.InterLock_Type == 1)
	{
		// 8Bit
		if (nInterLock_No <= 7)
		{
			if (nFlag)
			{
				DO_Control((OUT_CVNO1 + nInterLock_No), 1);
			}
			else
			{
				DO_Control((OUT_CVNO1 + nInterLock_No), 0);
			}
		}
	}
	else if (m_ExtSEnv1.StationEnv.InterLock_Type == 2)
	{
		// 지상반 통신
		if (nInterLock_No <= 49)
		{
			nByte_Index = nInterLock_No / 8;
			nBit_Index = nInterLock_No % 8;

			if (nFlag)
			{
				m_St.InterLock_CVNO[nByte_Index] |= cbits[nBit_Index];
			}
			else
			{
				m_St.InterLock_CVNO[nByte_Index] &= nbits[nBit_Index];
			}
		}
	}
}

void Station_Manual_Interlock_Control(INT08U nStatinNo, INT08U nFlag)
{
	INT08U nInterLock_No = 0;
	INT08U nByte_Index = 0;
	INT08U nBit_Index = 0;

	if (m_ExtSEnv1.StationEnv.InterLock_Type == 1)
	{
		// 8Bit
		if (m_pgmEnv.InterlockMode == ST_INTERLOCK_MODE_0)
		{
			nInterLock_No = (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No - 1);
			if (nInterLock_No <= 7)
			{
				if (nFlag)
				{
					DO_Control((OUT_CVNO1 + nInterLock_No), 1);
				}
				else
				{
					DO_Control((OUT_CVNO1 + nInterLock_No), 0);
				}
			}
		}
		else if (m_pgmEnv.InterlockMode == ST_INTERLOCK_MODE_HANKOOK_TIRE_TP2_DIR)
		{
			if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].Type == STATION_IN_TYPE)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

				if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].ForkDepth < 0)
				{
					// 좌측 입고
					if (nInterLock_No == 1)
					{
						(nFlag) ? DO_Control(OUT_CVNO1, 1) : DO_Control(OUT_CVNO1, 0);
					}
				}
				else
				{
					// 우측 입고
					if (nInterLock_No == 3)
					{
						(nFlag) ? DO_Control(OUT_CVNO3, 1) : DO_Control(OUT_CVNO3, 0);
					}
				}
			}
			else if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].Type == STATION_OUT_TYPE)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

				if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].ForkDepth < 0)
				{
					// 좌측 출고
					if (nInterLock_No == 2)
					{
						(nFlag) ? DO_Control(OUT_CVNO2, 1) : DO_Control(OUT_CVNO2, 0);
					}
				}
				else
				{
					// 우측 출고
					if (nInterLock_No == 4)
					{
						(nFlag) ? DO_Control(OUT_CVNO4, 1) : DO_Control(OUT_CVNO4, 0);
					}
				}
			}
			else if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].Type == STATION_IN_OUT_TYPE)
			{
				if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].ForkDepth < 0)
				{
					if (m_St.PosFork1.Position1.Bit.LiftUp_Left)
					{
						// 승강 상위치이면, 출고 인터록 신호 제어
						nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

						if (nInterLock_No == 2)
						{
							(nFlag) ? DO_Control(OUT_CVNO2, 1) : DO_Control(OUT_CVNO2, 0);
						}
					}
					else if (m_St.PosFork1.Position1.Bit.LiftDown_Left)
					{
						// 승강 하위치이면, 입고 인터록 신호 제어
						nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

						if (nInterLock_No == 1)
						{
							(nFlag) ? DO_Control(OUT_CVNO1, 1) : DO_Control(OUT_CVNO1, 0);
						}
					}
				}
				else
				{
					if (m_St.PosFork1.Position1.Bit.LiftUp_Right)
					{
						nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

						if (nInterLock_No == 4)
						{
							(nFlag) ? DO_Control(OUT_CVNO4, 1) : DO_Control(OUT_CVNO4, 0);
						}
					}
					else if (m_St.PosFork1.Position1.Bit.LiftDown_Right)
					{
						nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

						if (nInterLock_No == 3)
						{
							(nFlag) ? DO_Control(OUT_CVNO3, 1) : DO_Control(OUT_CVNO3, 0);
						}
					}
				}
			}
		}
		else if (m_pgmEnv.InterlockMode == ST_INTERLOCK_MODE_HANKOOK_TIRE_TP2_FlOOR_NO)
		{

			if (nStatinNo == 1)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

				if (nInterLock_No == 4)
				{
					(nFlag) ? DO_Control(OUT_CVNO4, 1) : DO_Control(OUT_CVNO4, 0);
				}
			}
			else if (nStatinNo == 2)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

				if (nInterLock_No == 3)
				{
					(nFlag) ? DO_Control(OUT_CVNO3, 1) : DO_Control(OUT_CVNO3, 0);
				}
			}
			else if (nStatinNo == 3)
			{
				if (m_St.Inv_St[INV_FORK_1].Status1.GoodsFlag_Or_MoveHome)
				{
					nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

					if (nInterLock_No == 2)
					{
						(nFlag) ? DO_Control(OUT_CVNO2, 1) : DO_Control(OUT_CVNO2, 0);
					}
				}
				else
				{
					nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

					if (nInterLock_No == 1)
					{
						(nFlag) ? DO_Control(OUT_CVNO1, 1) : DO_Control(OUT_CVNO1, 0);
					}
				}

			}
		}
	}
	else if (m_ExtSEnv1.StationEnv.InterLock_Type == 2)
	{
		// 지상반 통신
		nInterLock_No = (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No - 1);

		if (nInterLock_No <= 49)
		{
			nByte_Index = nInterLock_No / 8;
			nBit_Index = nInterLock_No % 8;

			if (nFlag)
			{
				m_St.InterLock_CVNO[nByte_Index] |= cbits[nBit_Index];
			}
			else
			{
				m_St.InterLock_CVNO[nByte_Index] &= nbits[nBit_Index];
			}
		}
	}
}

void Station_AutoMode_Interlock_Control(INT08U nStatinNo, INT08U nFlag, INT08U nForkJob)
{
	INT08U nInterLock_No = 0;
	INT08U nByte_Index = 0;
	INT08U nBit_Index = 0;

	nInterLock_No = (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No - 1);

	if (m_ExtSEnv1.StationEnv.InterLock_Type == 1)
	{
		// 8Bit
		if (m_pgmEnv.InterlockMode == ST_INTERLOCK_MODE_0)
		{
			if (nInterLock_No <= 7)
			{
				if (nFlag)
				{
					DO_Control((OUT_CVNO1 + nInterLock_No), 1);
				}
				else
				{
					DO_Control((OUT_CVNO1 + nInterLock_No), 0);
				}
			}
		}
		else if (m_pgmEnv.InterlockMode == ST_INTERLOCK_MODE_HANKOOK_TIRE_TP2_DIR)
		{
			if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].Type == STATION_IN_TYPE)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

				if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].ForkDepth < 0)
				{
					// 좌측 입고
					if (nInterLock_No == 1)
					{
						(nFlag) ? DO_Control(OUT_CVNO1, 1) : DO_Control(OUT_CVNO1, 0);
					}
				}
				else
				{
					// 우측 입고
					if (nInterLock_No == 3)
					{
						(nFlag) ? DO_Control(OUT_CVNO3, 1) : DO_Control(OUT_CVNO3, 0);
					}
				}
			}
			else if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].Type == STATION_OUT_TYPE)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

				if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].ForkDepth < 0)
				{
					// 좌측 출고
					if (nInterLock_No == 2)
					{
						(nFlag) ? DO_Control(OUT_CVNO2, 1) : DO_Control(OUT_CVNO2, 0);
					}
				}
				else
				{
					// 우측 출고
					if (nInterLock_No == 4)
					{
						(nFlag) ? DO_Control(OUT_CVNO4, 1) : DO_Control(OUT_CVNO4, 0);
					}
				}
			}
			else if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].Type == STATION_IN_OUT_TYPE)
			{
				if (nForkJob == WORK_FORK1_GET)
				{
					nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

					if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].ForkDepth < 0)
					{
						// 좌측 입고
						if (nInterLock_No == 1)
						{
							(nFlag) ? DO_Control(OUT_CVNO1, 1) : DO_Control(OUT_CVNO1, 0);
						}
					}
					else
					{
						// 우측 입고
						if (nInterLock_No == 3)
						{
							(nFlag) ? DO_Control(OUT_CVNO3, 1) : DO_Control(OUT_CVNO3, 0);
						}
					}
				}
				else if (nForkJob == WORK_FORK1_PUT)
				{
					nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

					if (m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].ForkDepth < 0)
					{
						// 좌측 출고
						if (nInterLock_No == 2)
						{
							(nFlag) ? DO_Control(OUT_CVNO2, 1) : DO_Control(OUT_CVNO2, 0);
						}
					}
					else
					{
						// 우측 출고
						if (nInterLock_No == 4)
						{
							(nFlag) ? DO_Control(OUT_CVNO4, 1) : DO_Control(OUT_CVNO4, 0);
						}
					}
				}
			}
		}
		else if (m_pgmEnv.InterlockMode == ST_INTERLOCK_MODE_HANKOOK_TIRE_TP2_FlOOR_NO)
		{
			if (nForkJob == WORK_FORK1_GET)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No;

				if (nStatinNo == 1)
				{
					if (nInterLock_No == 4)
					{
						(nFlag) ? DO_Control(OUT_CVNO4, 1) : DO_Control(OUT_CVNO4, 0);
					}
				}
				else if (nStatinNo == 3)
				{
					if (nInterLock_No == 1)
					{
						(nFlag) ? DO_Control(OUT_CVNO1, 1) : DO_Control(OUT_CVNO1, 0);
					}
				}
			}
			else if (nForkJob == WORK_FORK1_PUT)
			{
				nInterLock_No = m_ExtSEnv1.StationEnv.StationSet[nStatinNo - 1].InterLock_No_Out;

				if (nStatinNo == 2)
				{
					if (nInterLock_No == 3)
					{
						(nFlag) ? DO_Control(OUT_CVNO3, 1) : DO_Control(OUT_CVNO3, 0);
					}
				}
				else if (nStatinNo == 3)
				{
					if (nInterLock_No == 2)
					{
						(nFlag) ? DO_Control(OUT_CVNO2, 1) : DO_Control(OUT_CVNO2, 0);
					}
				}
			}
		}
	}
	else if (m_ExtSEnv1.StationEnv.InterLock_Type == 2)
	{
		// 지상반 통신
		if (nInterLock_No <= 49)
		{
			nByte_Index = nInterLock_No / 8;
			nBit_Index = nInterLock_No % 8;

			if (nFlag)
			{
				m_St.InterLock_CVNO[nByte_Index] |= cbits[nBit_Index];
			}
			else
			{
				m_St.InterLock_CVNO[nByte_Index] &= nbits[nBit_Index];
			}
		}
	}
}

/**
  * @brief			화물 이재 시, 싱글딥 이중입고 센서 상태
  * @param nDir		포크 좌/우 방향
  * @retval None
  */
INT08U Check_St_ForkOut_DSTx(INT08U nStationNo, INT08U nDir)
{
	INT08U nStNo = 0;
	INT08U nForkNo = POS_FORK_1;
	INT08U nResult = 0;

	if (nStationNo < m_ExtSEnv1.StationEnv.TotalUseCnt)
	{
		nStNo = nStationNo;

		if (m_ExtSEnv1.StationEnv.StationSet[nStNo].Station_DSTLR_Fault_Flag)
		{
			if (Check_DSTx_Sensor(nForkNo, nDir))
			{
				asm volatile("NOP");
			}
			else
			{
				nResult = 1;
			}
		}
		else
		{
			nResult = 1;
		}
	}

	return nResult;
}

/**
  * @brief			스테이션 위치에서 이중입고 센서 상태
  * @param nDir		포크 좌/우 방향
  * @retval 이중입고 감지 : 1, 미감지 : 0
  */
INT08U Check_St_ForkOut_DSTx_1(INT08U nStationNo)
{
	INT08U nStNo = 0, nDir = 0;
	INT08U nForkNo = POS_FORK_1;
	INT08U nResult = 0;

	if (nStationNo < m_ExtSEnv1.StationEnv.TotalUseCnt)
	{
		nStNo = nStationNo;

		if (m_ExtSEnv1.StationEnv.StationSet[nStNo].Station_DSTLR_Fault_Flag)
		{
			if (m_ExtSEnv1.StationEnv.StationSet[nStNo].ForkDepth > 0)
			{
				nDir = FORK_MOVE_RIGHT;
			}
			else
			{
				nDir = FORK_MOVE_LEFT;
			}

			if (Check_DSTx_Sensor(nForkNo, nDir))
			{
				nResult = 1;
			}
			else
			{
				nResult = 0;
			}
		}
		else
		{
			nResult = 0;
		}
	}

	return nResult;
}



/**
  * @brief			화물 이재 시, 싱글딥 이중입고 센서 상태
  * @param nDir		포크 좌/우 방향
  * @retval None
  */
INT08U Check_DSTx_Sensor(INT08U nFork, INT08U nDir)
{
	INT08U nSensor_In = 0;

	if (nFork == POS_FORK_1)
	{
		// Fork 1
		if (nDir == FORK_MOVE_LEFT)
		{
			// Left
			if (Get_DI_UseFlag(IN_DSTLe1))
			{
				if (m_DIO_SetInfo.Set.DI_Set[IN_DSTLe1].duplexing == 1)
				{
					// 이중화 OR 처리
					if (Get_DI_State(IN_DSTL1) || Get_DI_State(IN_DSTLe1))
					{
						nSensor_In = 1;
					}
				}
				else if (m_DIO_SetInfo.Set.DI_Set[IN_DSTLe1].duplexing == 2)
				{
					// 이중화 AND 처리
					if (Get_DI_State(IN_DSTL1) && Get_DI_State(IN_DSTLe1))
					{
						nSensor_In = 1;
					}
				}
				else
				{
					if (Get_DI_State(IN_DSTLe1))
					{
						nSensor_In = 1;
					}
				}
			}
			else
			{
				if (Get_DI_UseFlag(IN_DSTL1))
				{
					if (Get_DI_State(IN_DSTL1))
					{
						nSensor_In = 1;
					}
				}
			}
		}
		else
		{
			// Right
			if (Get_DI_UseFlag(IN_DSTRe1))
			{
				if (m_DIO_SetInfo.Set.DI_Set[IN_DSTRe1].duplexing == 1)
				{
					// 이중화 OR 처리
					if (Get_DI_State(IN_DSTR1) || Get_DI_State(IN_DSTRe1))
					{
						nSensor_In = 1;
					}
				}
				else if (m_DIO_SetInfo.Set.DI_Set[IN_DSTRe1].duplexing == 2)
				{
					// 이중화 AND 처리
					if (Get_DI_State(IN_DSTR1) && Get_DI_State(IN_DSTRe1))
					{
						nSensor_In = 1;
					}
				}
				else
				{
					if (Get_DI_State(IN_DSTRe1))
					{
						nSensor_In = 1;
					}
				}
			}
			else
			{
				if (Get_DI_UseFlag(IN_DSTR1))
				{
					if (Get_DI_State(IN_DSTR1))
					{
						nSensor_In = 1;
					}
				}
			}
		}
	}
	else
	{
		// Fork 2
		if (nDir == FORK_MOVE_LEFT)
		{
			// Left
			if (Get_DI_UseFlag(IN_DSTLe2))
			{
				if (m_DIO_SetInfo.Set.DI_Set[IN_DSTLe2].duplexing == 1)
				{
					// 이중화 OR 처리
					if (Get_DI_State(IN_DSTL2) || Get_DI_State(IN_DSTLe2))
					{
						nSensor_In = 1;
					}
				}
				else if (m_DIO_SetInfo.Set.DI_Set[IN_DSTLe2].duplexing == 2)
				{
					// 이중화 AND 처리
					if (Get_DI_State(IN_DSTL2) && Get_DI_State(IN_DSTLe2))
					{
						nSensor_In = 1;
					}
				}
				else
				{
					if (Get_DI_State(IN_DSTLe2))
					{
						nSensor_In = 1;
					}
				}
			}
			else
			{
				if (Get_DI_UseFlag(IN_DSTL2))
				{
					if (Get_DI_State(IN_DSTL2))
					{
						nSensor_In = 1;
					}
				}
			}
		}
		else
		{
			// Right
			if (Get_DI_UseFlag(IN_DSTRe2))
			{
				if (m_DIO_SetInfo.Set.DI_Set[IN_DSTRe2].duplexing == 1)
				{
					// 이중화 OR 처리
					if (Get_DI_State(IN_DSTR2) || Get_DI_State(IN_DSTRe2))
					{
						nSensor_In = 1;
					}
				}
				else if (m_DIO_SetInfo.Set.DI_Set[IN_DSTRe2].duplexing == 2)
				{
					// 이중화 AND 처리
					if (Get_DI_State(IN_DSTR2) && Get_DI_State(IN_DSTRe2))
					{
						nSensor_In = 1;
					}
				}
				else
				{
					if (Get_DI_State(IN_DSTRe2))
					{
						nSensor_In = 1;
					}
				}
			}
			else
			{
				if (Get_DI_UseFlag(IN_DSTR2))
				{
					if (Get_DI_State(IN_DSTR2))
					{
						nSensor_In = 1;
					}
				}
			}
		}
	}

	return nSensor_In;
}

