/**
  * @brief 자동 포크1 OUT 상태에서 승강 상승/하강 동작 후 포크센서(FEL1, FER1, FML1, FMR1) 감지 확인
  * @param None
  * @retval None
  */
INT08U Check_ForkOut_After_MoveLift_ForkSensor(INT08U nForkOpMode)
{
	INT08U nResult = 0;
	INT08U nErrorFlag = 0;

	if (m_ExtSEnv.Machine.mType.Fork_Type == FORK_TYPE_SINGLE_DEEP)
	{
		if ((nForkOpMode == FORK_MOVE_CENTER_TO_FEL_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FEL_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFEL == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FEL1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 15, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 3;
				}
			}

		}
		else if ((nForkOpMode == FORK_MOVE_CENTER_TO_FER_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FER_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFER == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FER1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 18, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 6;
				}
			}
		}
	}
	else
	{
		// FORK_TYPE_DOUBLE_DEEP_2POS, FORK_TYPE_DOUBLE_DEEP_3POS
		if ((nForkOpMode == FORK_MOVE_CENTER_TO_FEL_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FEL_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFEL == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FEL1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 15, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 3;
				}
			}
		}
		else if ((nForkOpMode == FORK_MOVE_CENTER_TO_FHL_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FHL_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFHL == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FHL1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 9, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 1;
				}
			}
		}
		else if ((nForkOpMode == FORK_MOVE_CENTER_TO_FML_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FML_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFML == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FML1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 10, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 2;
				}
			}
		}
		else if ((nForkOpMode == FORK_MOVE_CENTER_TO_FER_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FER_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFER == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FER1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 18, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 6;
				}
			}
		}
		else if ((nForkOpMode == FORK_MOVE_CENTER_TO_FHR_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FHR_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFHR == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FHR1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 16, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 4;
				}
			}
		}
		else if ((nForkOpMode == FORK_MOVE_CENTER_TO_FMR_NO_LOAD) \
			|| (nForkOpMode == FORK_MOVE_CENTER_TO_FMR_LOAD))
		{
			if (m_ExtSEnv2.ForkDrive.PosSensorUse.Setting.Bit.mFMR == FORK_POS_CEHCK_POS_SENSOR)
			{
				if (Get_DI_State(IN_FMR1) == 0)
				{
					save_error_code(ERROR1_FORK_SENSOR, 17, m_pgmEnv.SRM_RunMode);

					nErrorFlag = 5;
				}
			}
		}
	}

	if (nErrorFlag != 0)
	{
		//save_error_code(ERROR1_FORK_SENSOR, 9, nErrorFlag);

		nResult = 1;
	}

	return nResult;
}

/**
  * @brief
  * @param None
  * @retval None
  */
void Update_Invertor_Param()
{
	static INT32U s_Timer = 0;
	static INT32U s_CheckFlag = 0;

	//if (m_pgmEnv.SRM_Machine_State < SRM_MACHINE_DRIVE_ON)		return;

	if (s_CheckFlag)
	{
		if (getCalcTimer1ms(s_Timer) > 500)
		{
			s_Timer = m_pgmEnv.timer1ms;

			if (s_CheckFlag & cbits[INV_TRAVEL])
			{
				s_CheckFlag &= nbits[INV_TRAVEL];

				/*
				if (m_ExtSEnv2.TravDrive.InvParam.RefOffset != m_SRM_TxPDO[INV_TRAV].Acutal_RefOffset)
				{
					save_error_code(ERROR_TRAV_PARAM_DATA, 1, 0);
				}

				if (m_ExtSEnv2.TravDrive.InvParam.PosGain != m_SRM_TxPDO[INV_TRAV].Acutal_PosGain)
				{
					save_error_code(ERROR_TRAV_PARAM_DATA, 2, 0);
				}

				if (m_ExtSEnv2.TravDrive.InvParam.PosWindow != (INT08U)m_SRM_TxPDO[INV_TRAV].Acutal_PosWindow)
				{
					save_error_code(ERROR_TRAV_PARAM_DATA, 3, 0);
				}
				*/
			}

			if (s_CheckFlag & cbits[INV_HOIST])
			{
				s_CheckFlag &= nbits[INV_HOIST];

				/*
				if (m_ExtSEnv2.LiftDrive.InvParam.RefOffset != m_SRM_TxPDO[INV_LIFT].Acutal_RefOffset)
				{
					save_error_code(ERROR_LIFT_PARAM_DATA, 1, 0);
				}

				if (m_ExtSEnv2.LiftDrive.InvParam.PosGain != m_SRM_TxPDO[INV_LIFT].Acutal_PosGain)
				{
					save_error_code(ERROR_LIFT_PARAM_DATA, 2, 0);
				}

				if (m_ExtSEnv2.LiftDrive.InvParam.PosWindow != (INT08U)m_SRM_TxPDO[INV_LIFT].Acutal_PosWindow)
				{
					save_error_code(ERROR_LIFT_PARAM_DATA, 3, 0);
				}*/
			}

			if (s_CheckFlag & cbits[INV_FORK_1])
			{
				s_CheckFlag &= nbits[INV_FORK_1];

				/*
				if (m_ExtSEnv2.ForkDrive.InvParam.RefOffset != m_SRM_TxPDO[INV_FORK_1].Acutal_RefOffset)
				{
					save_error_code(ERROR_FORK_PARAM_DATA, 1, 0);
				}

				if (m_ExtSEnv2.ForkDrive.InvParam.PosGain != m_SRM_TxPDO[INV_FORK_1].Acutal_PosGain)
				{
					save_error_code(ERROR_FORK_PARAM_DATA, 2, 0);
				}

				if (m_ExtSEnv2.ForkDrive.InvParam.PosWindow != (INT08U)m_SRM_TxPDO[INV_FORK_1].Acutal_PosWindow)
				{
					save_error_code(ERROR_FORK_PARAM_DATA, 3, 0);
				}
				*/
			}
		}
	}
	else
	{
		if (getCalcTimer1ms(s_Timer) > 100)
		{
			if (((m_ExtSEnv2.TravDrive.InvParam.RefOffset != m_SRM_RxPDO[INV_TRAVEL].Set_RefOffset)) \
				|| ((m_ExtSEnv2.TravDrive.InvParam.PosGain != m_SRM_RxPDO[INV_TRAVEL].Set_PosGain)) \
				|| ((m_ExtSEnv2.TravDrive.InvParam.PosWindow != (INT08U)m_SRM_RxPDO[INV_TRAVEL].Set_PosWindow)))
			{
				Store_InvParam_RxPDO_Queue(INV_TRAVEL, 1, m_ExtSEnv2.TravDrive.InvParam.RefOffset, \
					m_ExtSEnv2.TravDrive.InvParam.PosGain, m_ExtSEnv2.TravDrive.InvParam.PosWindow);

				s_CheckFlag |= cbits[INV_TRAVEL];
			}

			if (((m_ExtSEnv2.LiftDrive.InvParam.RefOffset != m_SRM_RxPDO[INV_HOIST].Set_RefOffset)) \
				|| ((m_ExtSEnv2.LiftDrive.InvParam.PosGain != m_SRM_RxPDO[INV_HOIST].Set_PosGain)) \
				|| ((m_ExtSEnv2.LiftDrive.InvParam.PosWindow != (INT08U)m_SRM_RxPDO[INV_HOIST].Set_PosWindow)))
			{
				Store_InvParam_RxPDO_Queue(INV_HOIST, 1, m_ExtSEnv2.LiftDrive.InvParam.RefOffset, \
					m_ExtSEnv2.LiftDrive.InvParam.PosGain, m_ExtSEnv2.LiftDrive.InvParam.PosWindow);

				s_CheckFlag |= cbits[INV_HOIST];
			}

			if (((m_ExtSEnv2.ForkDrive.InvParam.RefOffset != m_SRM_RxPDO[INV_FORK_1].Set_RefOffset)) \
				|| ((m_ExtSEnv2.ForkDrive.InvParam.PosGain != m_SRM_RxPDO[INV_FORK_1].Set_PosGain)) \
				|| ((m_ExtSEnv2.ForkDrive.InvParam.PosWindow != (INT08U)m_SRM_RxPDO[INV_FORK_1].Set_PosWindow)))
			{
				Store_InvParam_RxPDO_Queue(INV_FORK_1, 1, m_ExtSEnv2.ForkDrive.InvParam.RefOffset, \
					m_ExtSEnv2.ForkDrive.InvParam.PosGain, m_ExtSEnv2.ForkDrive.InvParam.PosWindow);

				s_CheckFlag |= cbits[INV_FORK_1];
			}

			s_Timer = m_pgmEnv.timer1ms;
		}
	}
}

/**
  * @brief
  * @param None
  * @retval None
  */
void SRM_SetupMode_Position_Ctr_Proc(void)
{
	m_TestStatus.St[DEBUG_STR_8] = m_pgmEnv.Enable_Setup_Move_Position;

	if (m_pgmEnv.Enable_Setup_Move_Position)
	{
		m_TestStatus.St[DEBUG_STR_9] = getCalcTimer1ms(m_pgmEnv.Enable_Setup_Move_Position_Timer) / 1000;

		if (getCalcTimer1ms(m_pgmEnv.Enable_Setup_Move_Position_Timer) > (600 * 1000))
		{
			// 셋업모드 위치이동 지령이 10분동안 제어가 없으면 해제
			m_pgmEnv.Enable_Setup_Move_Position = 0;
		}
	}
	else
	{
		m_TestStatus.St[DEBUG_STR_9] = 0;
	}
}

