	//static INT32U s_TravProfileTime = 0;
	//static INT32U s_LiftProfileTime = 0;

	//INT08U nDEF_TravLift_Move_Mode = 0;	// 0 : 동시 주행, 1 : 리프트 상승 시 동시 도착

