		(Get_DI_State_Filter(IN_FCR1)) ? \
			(m_Send_HMI_Register.RealTime.Register.MW112.Bit.FCR1 = 1) : (m_Send_HMI_Register.RealTime.Register.MW112.Bit.FCR1 = 0);

		(Get_DI_State_Filter(IN_FCL1)) ? \
			(m_Send_HMI_Register.RealTime.Register.MW112.Bit.FCL1 = 1) : (m_Send_HMI_Register.RealTime.Register.MW112.Bit.FCL1 = 0);

