		(Get_DI_State_Filter(IN_LDD)) ? \
			(m_Send_HMI_Register.RealTime.Register.MW112.Bit.LDD = 1) : (m_Send_HMI_Register.RealTime.Register.MW112.Bit.LDD = 0);

